var TOPICS_DATA = TOPICS_DATA || {};
TOPICS_DATA["api-gateway"] = TOPICS_DATA["api-gateway"] || {};
TOPICS_DATA["api-gateway"]["ag-kong"] = {"id":"ag-kong","title":"Kong","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Kong is an open-source API Gateway built on NGINX and OpenResty, providing traffic control, security, analytics, and plugin extensibility.","Kong offers OSS (Community) and Enterprise editions. It operates in DB-mode (PostgreSQL/Cassandra) or DB-less (declarative config) mode.","Core concepts: Routes (match requests), Services (backend targets), Upstreams (load balancing), Consumers (auth entities), and Plugins (extensions).","Plugins cover auth (Key Auth, JWT, OAuth2), security (CORS, IP Restriction, Rate Limiting), traffic control, and observability (Prometheus, Datadog)."],"laymanDefinition":"Kong is like a smart security checkpoint at a corporate building. Every visitor (API request) passes through Kong. It checks their badge (auth), looks up their destination (routing), limits visitors (rate limiting), logs visits (logging), and directs them to the right office (backend).","deepDive":[{"heading":"Kong Architecture","text":"Kong runs on NGINX + OpenResty (Lua). Two processes: Kong (admin API + management) and OpenResty (proxy runtime). PostgreSQL in DB-mode. DB-less uses declarative YAML/JSON. Enterprise adds Kong Manager UI, Dev Portal, Vitals analytics."},{"heading":"Routes, Services, Upstreams","text":"Route: URL matching (paths, hosts, methods). Service: backend API abstraction. Upstream: load balancing group with health checks, circuit breakers, weighted round-robin across multiple targets."},{"heading":"Kong Plugin System","text":"Plugins run in lifecycle phases: rewrite, access (auth), header_filter, body_filter, log, timer. Custom plugins in Lua. Order: auth first, then rate-limit, transform, log. Precedence: global > consumer > route > service."},{"heading":"Authentication Plugins","text":"Key Auth: API key in header/query/body. Basic Auth: base64 credentials. JWT: RSA/HMAC validation. OAuth2: authorization code flow. HMAC Auth: request signing. LDAP Auth: enterprise directory. Session: cookie-based."}],"interviewAnswer":"Kong is the most popular open-source API gateway. It excels at plugin extensibility and supports DB-mode for dynamic routing and DB-less for GitOps. Use for microservices API management, rate limiting, auth centralization, and observability.","interviewQuestions":[{"question":"What is Kong?","answer":"An open-source API Gateway on NGINX/OpenResty with plugin-based extensibility for traffic control, security, and observability."},{"question":"What are the two Kong deployment modes?","answer":"DB-mode (PostgreSQL for dynamic config) and DB-less mode (declarative YAML/JSON, no database)."},{"question":"What are Kong Routes, Services, Upstreams?","answer":"Route: URL matching rules. Service: backend API abstraction. Upstream: load balancing group with health checks."},{"question":"What plugin lifecycle phases does Kong support?","answer":"rewrite, access (auth), header_filter, body_filter, log, timer."},{"question":"What does Enterprise add over OSS?","answer":"Kong Manager UI, Dev Portal, Vitals analytics, and enterprise-grade plugins."},{"question":"Can Kong work without a database?","answer":"Yes, DB-less mode uses a declarative config file. Config is static until file reload."},{"question":"What database does Kong support?","answer":"PostgreSQL (recommended) or Cassandra (legacy, deprecated in newer versions)."},{"question":"What are Kong Consumers?","answer":"Entities representing users or applications for auth, rate limiting, and ACL plugin configs."},{"question":"What is the plugin order of execution?","answer":"Global first, then consumer-level, route-level, then service-level plugins."},{"question":"What proxy does Kong use?","answer":"NGINX + OpenResty (Lua scripting engine for NGINX)."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Kong</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Client</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">API Consumer</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"200\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Kong</text><text x=\"200\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">API Gateway</text><line x1=\"250\" y1=\"48\" x2=\"280\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"150\" y1=\"60\" x2=\"150\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Route</text><text x=\"60\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">URL Match</text><line x1=\"110\" y1=\"83\" x2=\"140\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"200\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Plugins</text><text x=\"200\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auth->RateLimit->Log</text><line x1=\"250\" y1=\"83\" x2=\"280\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"150\" y1=\"90\" x2=\"150\" y2=\"110\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Service</text><text x=\"60\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Backend</text><line x1=\"110\" y1=\"118\" x2=\"140\" y2=\"118\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"200\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Upstream</text><text x=\"200\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">LB+Health</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Kong API Gateway</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">NGINX+OpenResty. Routes,Services,Plugins. DB or DB-less. OSS+Enterprise.</text></svg>","codeExamples":"<text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Kong: Open-source API Gateway on NGINX/OpenResty. Plugin-based, DB or DB-less modes.</text>","mcqQuestions":[{"title":"Kong Declarative Config (DB-less)","useCase":"Kong config via YAML.","code":"# kong.yml — declarative config\n_format_version: \"3.0\"\nservices:\n  - name: user-service\n    url: http://users-api:3000\n    routes:\n      - name: user-route\n        paths:\n          - /users\n        methods:\n          - GET\n        plugins:\n          - name: key-auth\n          - name: rate-limiting\n            config:\n              minute: 60\nconsumers:\n  - username: my-app\n    keyauth_credentials:\n      - key: abc123-secret-key","description":"Declarative Kong config for DB-less mode — ideal for GitOps."},{"title":"Kong Admin API (Create Service)","useCase":"REST API to configure Kong.","code":"# Create a Service\ncurl -s -X POST http://localhost:8001/services \\\n  -H \"Content-Type: application/json\" \\\n  -d '{\"name\":\"order-service\",\"url\":\"http://orders-api:4000\"}'\n# Create a Route\ncurl -s -X POST http://localhost:8001/services/order-service/routes \\\n  -H \"Content-Type: application/json\" \\\n  -d '{\"name\":\"order-route\",\"paths\":[\"/orders\"],\"methods\":[\"GET\",\"POST\"]}'\n# List services\ncurl -s http://localhost:8001/services | jq .","description":"Kong Admin API for dynamic service and route creation."},{"title":"Kong Plugin: Rate Limiting","useCase":"Rate limiting plugin.","code":"# Enable rate limiting on a route\ncurl -s -X POST http://localhost:8001/routes/order-route/plugins \\\n  -H \"Content-Type: application/json\" \\\n  -d '{\"name\":\"rate-limiting\",\"config\":{\"minute\":30,\"hour\":1000,\"policy\":\"redis\",\"redis_host\":\"redis-cluster\",\"redis_port\":6379}}'\n# Response headers: X-RateLimit-Limit-minute, X-RateLimit-Remaining-minute","description":"Rate limiting plugin with Redis-backed distributed counting."},{"title":"Kong Upstream with Health Checks","useCase":"Load balancing with health checks.","code":"# Create Upstream\ncurl -s -X POST http://localhost:8001/upstreams \\\n  -H \"Content-Type: application/json\" \\\n  -d '{\"name\":\"orders-upstream\",\"algorithm\":\"round-robin\",\"healthchecks\":{\"active\":{\"type\":\"http\",\"http_path\":\"/health\",\"healthy\":{\"interval\":5,\"successes\":1},\"unhealthy\":{\"interval\":5,\"http_failures\":3}}}}'\n# Add targets\ncurl -s -X POST http://localhost:8001/upstreams/orders-upstream/targets \\\n  -d '{\"target\":\"10.0.1.10:4000\",\"weight\":100}'\ncurl -s -X POST http://localhost:8001/upstreams/orders-upstream/targets \\\n  -d '{\"target\":\"10.0.1.11:4000\",\"weight\":50}'","description":"Kong upstream with active health checks and weighted targets."},{"question":"Kong — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Kong — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Kong — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Kong — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Kong — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Kong — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["api-gateway"]["ag-nginx-gateway"] = {"id":"ag-nginx-gateway","title":"NGINX API Gateway","difficulty":"intermediate","estimatedMinutes":20,"tldr":["NGINX is a high-performance web server, reverse proxy, and load balancer that can be configured as an API Gateway.","Core capabilities: request routing, SSL/TLS termination, rate limiting, authentication, caching, request/response transformation.","NGINX uses declarative config: http, server, location, upstream blocks. NGINX Plus adds active health checks, JWT validation, session persistence, key-value store.","NGINX excels at rate limiting (leaky bucket), SSL termination, caching (proxy_cache), and request routing with regex location matching."],"laymanDefinition":"NGINX as an API Gateway is like a highly efficient postal sorting facility. Mail (API request) arrives, address checked (URL), postage verified (rate limit), sender ID checked (auth), sorted to correct bin (routing), delivery logged (logging). All processing at lightning speed.","deepDive":[{"heading":"NGINX as Reverse Proxy","text":"NGINX receives client requests and forwards to backends via proxy_pass. Benefits: single entry point, backend isolation, centralized SSL termination, response buffering, error handling. Supports WebSocket proxying via upgrade headers."},{"heading":"Rate Limiting with NGINX","text":"limit_req_zone defines shared memory zone with rate. limit_req applies it. Leaky bucket: burst allows spikes, nodelay returns 503 immediately. Can limit by IP ($binary_remote_addr) or other variables."},{"heading":"Auth in NGINX","text":"Basic Auth: auth_basic + htpasswd file. Subrequest auth: auth_request to external auth service. JWT (NGINX Plus): auth_jwt + auth_jwt_key_file. Client cert auth: ssl_client_certificate."},{"heading":"Caching for APIs","text":"proxy_cache_path /data/nginx/cache keys_zone=api_cache:10m levels=1:2 max_size=1g inactive=60m. proxy_cache api_cache; proxy_cache_valid 200 1m; proxy_cache_use_stale error timeout;."}],"interviewAnswer":"NGINX is the most performant API Gateway for simple to moderate traffic. It excels at rate limiting, SSL termination, caching, and routing. Config model is powerful but complex. NGINX Plus adds enterprise features. Consider Kong (on NGINX/OpenResty) for complex routing.","interviewQuestions":[{"question":"What is NGINX?","answer":"High-performance web server, reverse proxy, and load balancer functioning as an API Gateway."},{"question":"How does NGINX handle routing?","answer":"Through server blocks (virtual hosts) and location blocks (URL path matching with regex)."},{"question":"What is proxy_pass?","answer":"Directive that forwards requests to a backend server or upstream group."},{"question":"How does NGINX rate limiting work?","answer":"Define limit_req_zone (shared memory + rate) and apply with limit_req. Leaky bucket algorithm."},{"question":"What does NGINX Plus add over OSS?","answer":"Active health checks, JWT validation, key-value store, session persistence, extended monitoring."},{"question":"How to add auth in NGINX?","answer":"Basic Auth (htpasswd), subrequest to auth service, client certificates, or JWT (Plus)."},{"question":"What is the upstream block for?","answer":"Defines backend server group with load balancing (round-robin, least_conn, ip_hash)."},{"question":"How does NGINX handle SSL?","answer":"ssl_certificate and ssl_certificate_key directives. Terminates SSL, proxies over HTTP."},{"question":"What is nodelay in rate limiting?","answer":"Returns 503 immediately when burst exceeded instead of queuing."},{"question":"How does NGINX cache API responses?","answer":"Define proxy_cache_path with cache zone, enable with proxy_cache."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">NGINX API Gateway</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Client</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">HTTP request</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"200\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">NGINX</text><text x=\"200\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Reverse Proxy</text><line x1=\"250\" y1=\"48\" x2=\"280\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"150\" y1=\"60\" x2=\"150\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Rate Limit</text><text x=\"60\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">limit_req</text><line x1=\"110\" y1=\"83\" x2=\"140\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"200\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Auth</text><text x=\"200\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Basic/JWT</text><line x1=\"250\" y1=\"83\" x2=\"280\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"150\" y1=\"90\" x2=\"150\" y2=\"110\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cache</text><text x=\"60\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">proxy_cache</text><line x1=\"110\" y1=\"118\" x2=\"140\" y2=\"118\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"200\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Upstream</text><text x=\"200\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">LB Backend</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">NGINX API Gateway</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">High-performance reverse proxy. Rate limiting, auth, caching, SSL termination, load balancing.</text></svg>","codeExamples":"<text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">NGINX: Ultra-fast reverse proxy and API Gateway. Config-driven rate limiting, auth, caching, load balancing.</text>","mcqQuestions":[{"title":"Basic NGINX API Gateway Config","useCase":"Reverse proxy with routing.","code":"http {\n  upstream backend {\n    server api1.example.com:3000 weight=3;\n    server api2.example.com:3000;\n  }\n  server {\n    listen 443 ssl;\n    server_name api.myapp.com;\n    ssl_certificate /etc/ssl/certs/api.crt;\n    ssl_certificate_key /etc/ssl/private/api.key;\n    location /users/ { proxy_pass http://user-service:4000; }\n    location /orders/ { proxy_pass http://backend; }\n    location /health { return 200 \"OK\"; }\n  }\n}","description":"Basic NGINX API Gateway with upstream, SSL, and routing."},{"title":"NGINX Rate Limiting","useCase":"Limit per client IP.","code":"http {\n  limit_req_zone $binary_remote_addr zone=api_limit:10m rate=10r/s;\n  server {\n    location /api/ {\n      limit_req zone=api_limit burst=20 nodelay;\n      limit_req_status 429;\n      proxy_pass http://backend;\n    }\n  }\n}","description":"NGINX rate limiting with burst and nodelay."},{"title":"JWT Validation (NGINX Plus)","useCase":"Validate JWT.","code":"http {\n  auth_jwt_key_cache_ttl 600;\n  server {\n    location /api/secure/ {\n      auth_jwt \"Secure API\" token=$http_authorization;\n      auth_jwt_key_file /etc/nginx/jwks.json;\n      proxy_set_header X-User-ID $jwt_payload_sub;\n      proxy_set_header X-User-Role $jwt_payload_role;\n      proxy_pass http://backend;\n    }\n  }\n}","description":"NGINX Plus JWT validation with claim extraction."},{"title":"NGINX Response Caching","useCase":"Cache backend responses.","code":"http {\n  proxy_cache_path /var/cache/nginx levels=1:2 keys_zone=api_cache:10m max_size=1g inactive=60m;\n  server {\n    location /api/products/ {\n      proxy_cache api_cache;\n      proxy_cache_valid 200 302 5m;\n      proxy_cache_use_stale error timeout updating;\n      add_header X-Cache-Status $upstream_cache_status;\n      proxy_pass http://product-service:5000;\n    }\n  }\n}","description":"NGINX response caching with stale-while-revalidate."},{"title":"Basic Auth with htpasswd","useCase":"Simple auth.","code":"# htpasswd -c /etc/nginx/.htpasswd user1\nserver {\n  location /api/admin/ {\n    auth_basic \"Admin Area\";\n    auth_basic_user_file /etc/nginx/.htpasswd;\n    proxy_pass http://admin-service:6000;\n  }\n}","description":"Basic Auth and subrequest-based auth pattern."},{"question":"NGINX API Gateway — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"NGINX API Gateway — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"NGINX API Gateway — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"NGINX API Gateway — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"NGINX API Gateway — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["api-gateway"]["ag-ambassador"] = {"id":"ag-ambassador","title":"Ambassador","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Ambassador (CNCF project) is a Kubernetes-native API Gateway built on Envoy Proxy, designed for cloud-native microservices.","Ambassador uses declarative config through Kubernetes CRDs — no separate config files needed.","Key resources: Mapping (route), Module (global config), Filter (auth/transform), RateLimit, AuthService, TracingService, DevPortal.","Ambassador integrates with service meshes and supports gRPC, WebSocket, OpenAPI, and external auth natively."],"laymanDefinition":"Ambassador is like a building concierge in a smart apartment complex (Kubernetes). Instead of a separate rulebook, the concierge reads instructions posted on each apartment door (Kubernetes CRDs). When a delivery arrives (API request), the concierge checks instructions, verifies ID (auth), and routes to the correct apartment.","deepDive":[{"heading":"Ambassador Architecture","text":"Runs as a K8s deployment with Envoy Proxy as data plane. Agent watches K8s resources and updates Envoy config via xDS APIs. Key CRDs: Mapping (route rules), Module (HTTP settings), Filter (auth/transform), RateLimitService, AuthService."},{"heading":"Ambassador Mappings","text":"Mapping CRDs define how requests route to services. Key fields: prefix (URL), host (domain), service (backend), rewrite, method, headers, timeout, cors. Can reference Filters and RateLimits."},{"heading":"Auth in Ambassador","text":"External auth: AuthService CRD points to external HTTP service, returns 200 (allow) or 401/403 (deny). Built-in Filters: JWT (JWKS-based), OAuth2, Basic Auth. No external service needed for these."},{"heading":"Rate Limiting","text":"RateLimitService CRD configures an external rate limit service. RateLimit CRD defines label-based limits. Supports per-user, per-IP, per-route domains with configurable limits."}],"interviewAnswer":"Ambassador is the best choice for Kubernetes-native environments. Use Mappings for routing, Filters for auth, RateLimits for traffic control. CRD-based config is ideal for GitOps. Works well with service meshes. Strong alternative to Kong for cloud-native.","interviewQuestions":[{"question":"What is Ambassador?","answer":"K8s-native API Gateway on Envoy Proxy, using CRDs for declarative config."},{"question":"What does a Mapping define?","answer":"Route rules: URL prefix, host, backend service, rewrite, methods, timeouts, CORS."},{"question":"How does Ambassador handle auth?","answer":"Via AuthService (external HTTP) or built-in Filters (JWT, OAuth2, Basic Auth)."},{"question":"What proxy does Ambassador use?","answer":"Envoy Proxy — high-performance C++ proxy from Lyft."},{"question":"How does Ambassador configure itself?","answer":"Watches K8s CRDs (Mappings, Filters, RateLimits) and updates Envoy via xDS."},{"question":"Difference between Ambassador and Kong?","answer":"Ambassador is K8s-native (CRD-based). Kong is platform-agnostic with REST admin API."},{"question":"What is an AuthService CRD?","answer":"Defines external HTTP service that validates auth for incoming requests."},{"question":"Can Ambassador route gRPC?","answer":"Yes, via the grpc flag in Mappings."},{"question":"What is the Filter CRD?","answer":"Defines request/response transformations: JWT validation, header mods, OAuth."},{"question":"What is DevPortal CRD?","answer":"Serves an API documentation portal from OpenAPI specs and markdown."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Ambassador</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Client</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">External</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"200\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Ambassador</text><text x=\"200\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Envoy Proxy</text><line x1=\"250\" y1=\"48\" x2=\"280\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"150\" y1=\"60\" x2=\"150\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Mapping</text><text x=\"60\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Route rule</text><line x1=\"110\" y1=\"83\" x2=\"140\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"200\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">AuthService</text><text x=\"200\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">External auth</text><line x1=\"250\" y1=\"83\" x2=\"280\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"150\" y1=\"90\" x2=\"150\" y2=\"110\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">RateLimit</text><text x=\"60\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Traffic control</text><line x1=\"110\" y1=\"118\" x2=\"140\" y2=\"118\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"200\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">k8s Service</text><text x=\"200\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Backend</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Ambassador API Gateway</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">K8s-native on Envoy. CRD-based Mappings, Filters, AuthService, RateLimits.</text></svg>","codeExamples":"<text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Ambassador: K8s-native API Gateway on Envoy. Configured via CRDs: Mappings, Filters, AuthService.</text>","mcqQuestions":[{"title":"Basic Mapping CRD","useCase":"Route external traffic.","code":"apiVersion: getambassador.io/v3alpha1\nkind: Mapping\nmetadata:\n  name: user-service-mapping\nspec:\n  hostname: \"*\"\n  prefix: /api/users/\n  service: user-service:3000\n  rewrite: /\n  timeout_ms: 30000\n  cors:\n    origins:\n    - https://myapp.com\n    methods: GET, POST, PUT, DELETE","description":"Ambassador Mapping CRD for routing to a K8s service."},{"title":"AuthService (External Auth)","useCase":"Delegate auth.","code":"apiVersion: getambassador.io/v3alpha1\nkind: AuthService\nmetadata:\n  name: external-auth\nspec:\n  auth_service: auth-service:8000\n  proto: http\n  timeout_ms: 5000\n  allowed_headers:\n    - Authorization\n    - Cookie\n    - X-User-ID","description":"AuthService delegates auth to an external HTTP service."},{"title":"JWT Filter","useCase":"Built-in JWT validation.","code":"apiVersion: getambassador.io/v3alpha1\nkind: Filter\nmetadata:\n  name: jwt-filter\nspec:\n  JWT:\n    issuer: https://auth.example.com\n    audiences:\n    - my-api\n    jwksURI: https://auth.example.com/.well-known/jwks.json\n    forward_token: true\n---\napiVersion: getambassador.io/v3alpha1\nkind: Mapping\nmetadata:\n  name: secure-mapping\nspec:\n  prefix: /api/secure/\n  service: secure-service:4000\n  filters:\n  - name: jwt-filter","description":"JWT Filter with JWKS URI for key rotation."},{"title":"Rate Limiting CRD","useCase":"Label-based limits.","code":"apiVersion: getambassador.io/v3alpha1\nkind: RateLimit\nmetadata:\n  name: user-rate-limit\nspec:\n  domain: ambassador\n  descriptors:\n    - key: user-label\n      value: \"default\"\n      rate_per_unit: 100\n      unit: minute\n---\napiVersion: getambassador.io/v3alpha1\nkind: RateLimitService\nmetadata:\n  name: ratelimit-svc\nspec:\n  service: \"edge-stack:8081\"\n  proto: grpc\n  timeout_ms: 100","description":"Label-based rate limiting with per-descriptor limits."},{"question":"Ambassador — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Ambassador — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Ambassador — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Ambassador — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Ambassador — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Ambassador — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["api-gateway"]["ag-traefik"] = {"id":"ag-traefik","title":"Traefik","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Traefik is a cloud-native reverse proxy and API Gateway that auto-discovers services from Docker, Kubernetes, Consul, and more.","Key concepts: EntryPoints (ports), Routers (request matching), Middlewares (processing chain), Services (backends).","Traefik auto-discovers from Docker labels, K8s Ingress/CRDs, Consul, etcd — no manual config needed.","Built-in middlewares: RateLimit, CircuitBreaker, Retry, BasicAuth, ForwardAuth, Headers, IPWhiteList, RedirectRegex, Compress."],"laymanDefinition":"Traefik is like an airport air traffic controller that knows every plane (service). When a flight (API request) comes in, the controller directs it to the correct gate (service). If a gate closes (service failure), traffic reroutes automatically. New planes discovered automatically.","deepDive":[{"heading":"Auto Service Discovery","text":"Traefik watches provider APIs: K8s (Ingress/CRD/Service), Docker (container labels), Consul/etcd (KV stores). New service deployed = Traefik auto-creates routers and updates LB — no config reload needed."},{"heading":"Routers and Middlewares","text":"Router matches by host, path, method, headers, query params. Routes to Service through Middleware chain: RateLimit -> Retry -> ForwardAuth -> AddHeader -> Service. Middlewares reusable across routers."},{"heading":"TCP and UDP Support","text":"TCP and UDP routing beyond HTTP. TCP routers match by SNI and port. Ideal for databases, gRPC, WebSockets. TCP middlewares: IPWhiteList, RateLimit."},{"heading":"Dashboard and Metrics","text":"Built-in dashboard at :8080. Routers, services, middlewares, health. Metrics: Prometheus, Datadog, InfluxDB, StatsD, OpenTelemetry. Access logs in JSON or common format."}],"interviewAnswer":"Traefik is the easiest API Gateway for auto-discovery environments. Minimal config on K8s or Docker. Clean middleware chain model. Built-in dashboard and metrics. Best for simple to moderate setups; consider Kong for complex enterprise needs.","interviewQuestions":[{"question":"What is Traefik?","answer":"Cloud-native reverse proxy with auto-discovery from Docker, K8s, Consul, and more."},{"question":"Main concepts?","answer":"EntryPoints (ports), Routers (matching), Middlewares (processing), Services (backends)."},{"question":"How does Traefik discover services?","answer":"Auto from Docker labels, K8s CRDs/Ingress, Consul, etcd."},{"question":"What is a Middleware?","answer":"Request/response processing: rate limiting, auth, headers, redirect, retry, circuit breaker."},{"question":"Does Traefik support TCP?","answer":"Yes, with SNI matching for databases, gRPC, WebSockets."},{"question":"How does Traefik handle SSL?","answer":"Automatic Let\\'s Encrypt via ACME. Wildcard and custom certs."},{"question":"v1 vs v2 difference?","answer":"v2: TCP/UDP routing, middleware CRDs, redesigned config."},{"question":"Metrics providers?","answer":"Prometheus, Datadog, InfluxDB, StatsD, OpenTelemetry."},{"question":"Canary deployments?","answer":"Yes, via weighted round-robin with traffic splitting."},{"question":"Dashboard?","answer":"Web UI at :8080 showing routers, services, middlewares, health."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Traefik</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Client</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">api.myapp.com</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"200\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">EntryPoint</text><text x=\"200\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Port 443</text><line x1=\"150\" y1=\"60\" x2=\"150\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Router</text><text x=\"60\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Host+Path match</text><line x1=\"110\" y1=\"83\" x2=\"140\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"200\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Middlewares</text><text x=\"200\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">RateLimit->Auth->Retry</text><line x1=\"250\" y1=\"83\" x2=\"280\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"150\" y1=\"90\" x2=\"150\" y2=\"110\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Service</text><text x=\"60\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Backend</text><line x1=\"110\" y1=\"118\" x2=\"140\" y2=\"118\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"200\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Discovery</text><text x=\"200\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Docker/k8s/Consul</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Traefik API Gateway</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auto-discovery. EntryPoints,Routers,Middlewares,Services. Let's Encrypt, dashboard.</text></svg>","codeExamples":"<text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Traefik: Cloud-native reverse proxy with auto-discovery. Routers+Middlewares+Services.</text>","mcqQuestions":[{"title":"Traefik Docker Labels","useCase":"Docker label config.","code":"version: \"3.8\"\nservices:\n  whoami:\n    image: traefik/whoami\n    labels:\n      - \"traefik.enable=true\"\n      - \"traefik.http.routers.whoami.rule=Host(`api.myapp.com`) && PathPrefix(`/whoami`)\"\n      - \"traefik.http.routers.whoami.entrypoints=web-secure\"\n      - \"traefik.http.routers.whoami.tls=true\"\n      - \"traefik.http.services.whoami.loadbalancer.server.port=80\"\n      - \"traefik.http.middlewares.rate-limit.ratelimit.average=100\"\n      - \"traefik.http.routers.whoami.middlewares=rate-limit@docker\"","description":"Traefik Docker labels for routing, TLS, rate limiting."},{"title":"Traefik K8s IngressRoute","useCase":"CRD with canary.","code":"apiVersion: traefik.io/v1alpha1\nkind: IngressRoute\nmetadata:\n  name: api-ingress\nspec:\n  entryPoints:\n    - web-secure\n  routes:\n    - kind: Rule\n      match: Host(`api.myapp.com`) && PathPrefix(`/users`)\n      services:\n        - name: user-service\n          port: 3000\n          weight: 80\n        - name: user-service-v2\n          port: 3000\n          weight: 20\n      middlewares:\n        - name: rate-limit\n  tls:\n    certResolver: letsencrypt","description":"K8s IngressRoute with canary (80/20) traffic split."},{"title":"Traefik Static Config (traefik.yml)","useCase":"Server-level config.","code":"entryPoints:\n  web:\n    address: \":80\"\n    http:\n      redirections:\n        entryPoint:\n          to: web-secure\n          scheme: https\n  web-secure:\n    address: \":443\"\nproviders:\n  docker:\n    endpoint: \"unix:///var/run/docker.sock\"\n  kubernetesCRD:\n    enabled: true\ncertificatesResolvers:\n  letsencrypt:\n    acme:\n      email: admin@myapp.com\n      storage: /certs/acme.json\n      httpChallenge:\n        entryPoint: web\nmetrics:\n  prometheus:\n    addEntryPointsLabels: true","description":"Traefik static config with Let\\'s Encrypt and auto-discovery."},{"title":"ForwardAuth Middleware","useCase":"External auth.","code":"apiVersion: traefik.io/v1alpha1\nkind: Middleware\nmetadata:\n  name: forward-auth\nspec:\n  forwardAuth:\n    address: \"http://auth-service:8000/validate\"\n    trustForwardHeader: true\n    authResponseHeaders:\n      - X-Auth-User\n      - X-Auth-Role","description":"ForwardAuth delegates auth to external service."},{"title":"Rate Limiting Middleware","useCase":"Traffic control.","code":"apiVersion: traefik.io/v1alpha1\nkind: Middleware\nmetadata:\n  name: rate-limit\nspec:\n  rateLimit:\n    average: 100\n    burst: 200\n    period: 1m","description":"Rate limiting middleware."},{"question":"Traefik — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Traefik — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Traefik — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Traefik — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Traefik — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["api-gateway"]["ag-aws-api-gateway"] = {"id":"ag-aws-api-gateway","title":"AWS API Gateway","difficulty":"intermediate","estimatedMinutes":20,"tldr":["AWS API Gateway is a fully managed service for creating, publishing, and securing REST, HTTP, and WebSocket APIs at any scale.","Three types: REST API (full-featured, API keys, usage plans, VTL), HTTP API (simpler, cheaper, faster, ideal for Lambda), WebSocket API (real-time).","Features: request throttling, API key management, usage plans, VTL mapping templates, caching, CORS, custom domains, CloudWatch logging.","Integrates with Lambda (proxy), DynamoDB (direct), Kinesis, SQS, Step Functions, VPC via NLB/ALB (VPC Link)."],"laymanDefinition":"AWS API Gateway is like a fully automated airport terminal managed by AWS. You tell them gates (endpoints), who can board (auth), and passenger limits (rate limiting). They handle building, security, maintenance. You focus on flights (backend). Everything scales automatically — pay per passenger.","deepDive":[{"heading":"REST vs HTTP vs WebSocket API","text":"REST API: feature-rich, API keys, usage plans, VTL mapping, WAF. HTTP API: simpler, ~70% cheaper, native OIDC/OAuth2, JWT authorizers, CORS auto-config. WebSocket: $connect/$disconnect/$default routes, callback URLs for push."},{"heading":"API Gateway Authorizers","text":"Cognito User Pools: JWT from AWS Cognito. Lambda Authorizer: custom auth in Lambda. IAM Authorizer: AWS SigV4 signing. JWT Authorizer (HTTP API): validate from OIDC issuer. API Keys: simple key-based."},{"heading":"Throttling and Usage Plans","text":"Account-level: default 10,000 rps. Usage Plan: per-API limits (rate + burst) tied to API keys. Per-client, per-method, global. 429 Too Many Requests with Retry-After."},{"heading":"Request/Response Transformation","text":"VTL (Velocity Template Language) mapping templates transform payloads. Convert REST JSON to SOAP XML, filter fields, rename params. HTTP API: use Lambda for transformation."}],"interviewAnswer":"AWS API Gateway is best for serverless on AWS. Use HTTP API for Lambda (cheaper, faster). Use REST for advanced features (API keys, usage plans, VTL). Use WebSocket for real-time. Enable caching for read-heavy endpoints. Combine with WAF for DDoS protection.","interviewQuestions":[{"question":"What is AWS API Gateway?","answer":"Managed service for creating, publishing, and securing REST, HTTP, and WebSocket APIs."},{"question":"Three API types?","answer":"REST (full-featured), HTTP (simpler/cheaper), WebSocket (real-time)."},{"question":"What is a Lambda Authorizer?","answer":"Custom auth Lambda that validates tokens and returns IAM policies."},{"question":"What is a Usage Plan?","answer":"Throttling and quota limits for API consumers identified by API keys."},{"question":"How does API Gateway throttle?","answer":"Account-level, Usage Plan, and method-level with rate/burst settings."},{"question":"What is VTL?","answer":"Velocity Template Language for request/response mapping templates."},{"question":"Difference between REST and HTTP API?","answer":"HTTP API is simpler, ~70% cheaper, OIDC/JWT native, no VTL."},{"question":"Can API Gateway integrate with VPC?","answer":"Yes, via VPC Link — private integration with NLB/ALB in a VPC."},{"question":"How does WebSocket API work?","answer":"$connect/$disconnect/$default routes with callback URLs."},{"question":"What caching does API Gateway support?","answer":"Per-stage caching with configurable TTL (default 300s)."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">AWS API Gateway</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Client</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Mobile/Web</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"200\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">API Gateway</text><text x=\"200\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Managed endpoint</text><line x1=\"250\" y1=\"48\" x2=\"280\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"150\" y1=\"60\" x2=\"150\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Auth</text><text x=\"60\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cognito/Lambda/IAM</text><line x1=\"110\" y1=\"83\" x2=\"140\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"200\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Throttle</text><text x=\"200\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Rate+burst limits</text><line x1=\"250\" y1=\"83\" x2=\"280\" y2=\"83\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"150\" y1=\"90\" x2=\"150\" y2=\"110\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Transform</text><text x=\"60\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">VTL mapping</text><line x1=\"110\" y1=\"118\" x2=\"140\" y2=\"118\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"200\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Lambda/HTTP</text><text x=\"200\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Backend</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">AWS API Gateway</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Managed: REST, HTTP, WebSocket. Cognito/Lambda auth, throttling, usage plans, VTL, caching.</text></svg>","codeExamples":"<text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">AWS API Gateway: Managed REST, HTTP, WebSocket. Auth, throttling, caching, VTL.</text>","mcqQuestions":[{"title":"AWS SAM: REST API with Lambda","useCase":"Serverless API.","code":"AWSTemplateFormatVersion: \"2010-09-09\"\nTransform: AWS::Serverless-2016-10-31\nGlobals:\n  Function:\n    Runtime: nodejs18.x\n    Timeout: 10\nResources:\n  OrderApi:\n    Type: AWS::Serverless::Api\n    Properties:\n      StageName: prod\n      Auth:\n        DefaultAuthorizer: CognitoAuthorizer\n        Authorizers:\n          CognitoAuthorizer:\n            UserPoolArn: !GetAtt UserPool.Arn\n      Throttle:\n        BurstLimit: 200\n        RateLimit: 100\n  GetOrdersFunction:\n    Type: AWS::Serverless::Function\n    Properties:\n      CodeUri: ./src\n      Handler: orders.getOrders\n      Events:\n        ApiEvent:\n          Type: Api\n          Properties:\n            RestApiId: !Ref OrderApi\n            Path: /orders\n            Method: GET","description":"SAM template for REST API with Cognito auth and throttling."},{"title":"AWS CLI: Create HTTP API","useCase":"CLI API creation.","code":"aws apigatewayv2 create-api \\\n  --name \"my-http-api\" --protocol-type HTTP \\\n  --target \"arn:aws:lambda:us-east-1:123456:function:my-function\"\naws apigatewayv2 create-stage --api-id abc123 --stage-name prod --auto-deploy\naws apigatewayv2 create-authorizer --api-id abc123 --authorizer-type JWT --name \"jwt-auth\" \\\n  --identity-source \"$request.header.Authorization\" \\\n  --jwt-configuration Audience=my-api,Issuer=\"https://cognito-idp.us-east-1.amazonaws.com/us-east-1_abc123\"\naws apigatewayv2 create-deployment --api-id abc123 --stage-name prod","description":"AWS CLI commands for HTTP API with JWT authorizer."},{"title":"Lambda Authorizer","useCase":"Custom auth.","code":"exports.handler = async (event) => {\n  try {\n    const token = event.authorizationToken.replace(\"Bearer \", \"\");\n    const decoded = jwt.verify(token, process.env.JWT_SECRET);\n    return {\n      principalId: decoded.sub,\n      policyDocument: {\n        Version: \"2012-10-17\",\n        Statement: [{\n          Action: \"execute-api:Invoke\",\n          Effect: \"Allow\",\n          Resource: event.methodArn\n        }],\n      },\n      context: { userId: decoded.sub, role: decoded.role },\n    };\n  } catch { throw new Error(\"Unauthorized\"); }\n};","description":"Lambda Authorizer validates JWT and returns IAM policy."},{"title":"VTL Mapping Template","useCase":"Request transformation.","code":"#set($inputRoot = $input.path(\"$\"))\n{\n  \"httpMethod\": \"$context.httpMethod\",\n  \"requestId\": \"$context.requestId\",\n  \"body\": $input.json(\"$\"),\n  \"params\": {\n    #foreach($param in $input.params().querystring.keySet())\n      \"$param\": \"$input.params().querystring.get($param)\"\n      #if($foreach.hasNext),#end\n    #end\n  }\n}","description":"VTL mapping template transforms request before forwarding."},{"title":"CDK Infrastructure","useCase":"Infra as code.","code":"import * as apigw from \"aws-cdk-lib/aws-apigateway\";\nimport * as lambda from \"aws-cdk-lib/aws-lambda\";\nconst handler = new lambda.Function(this, \"Handler\", {\n  runtime: lambda.Runtime.NODEJS_18_X,\n  handler: \"index.handler\",\n  code: lambda.Code.fromAsset(\"./src\"),\n});\nconst api = new apigw.LambdaRestApi(this, \"OrdersApi\", { handler, proxy: false });\nconst orders = api.root.addResource(\"orders\");\norders.addMethod(\"GET\");\nconst plan = api.addUsagePlan(\"UsagePlan\", {\n  name: \"Basic\",\n  throttle: { rateLimit: 10, burstLimit: 20 },\n  quota: { limit: 10000, period: apigw.Period.MONTH },\n});\nconst key = api.addApiKey(\"ApiKey\");\nplan.addApiKey(key);","description":"CDK for API Gateway with usage plan."},{"question":"AWS API Gateway — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"AWS API Gateway — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"AWS API Gateway — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"AWS API Gateway — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"AWS API Gateway — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["api-gateway"]["ag-rate-limiting"] = {"id":"ag-rate-limiting","title":"Rate Limiting","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Rate limiting controls how many requests a client can make within a time window. Prevents abuse, ensures fair usage, protects backends.","Common algorithms: Token Bucket (bursts), Leaky Bucket (smoothes), Fixed Window (simple, edge bursts), Sliding Window Log (precise), Sliding Window Counter (efficient+precise).","Applied per client (IP, API key, user ID): global, per-endpoint, or per-user tier. HTTP: 429 Too Many Requests with Retry-After.","Headers: X-RateLimit-Limit, X-RateLimit-Remaining, X-RateLimit-Reset."],"laymanDefinition":"Rate limiting is like a club with capacity limit. The bouncer counts: \"10 per minute\". Enter too fast: \"Wait 6 seconds\" (Retry-After). VIP members get faster entry (higher limits). Token Bucket system: tokens added every second, spend one to enter.","deepDive":[{"heading":"Token Bucket Algorithm","text":"Bucket holds N tokens, filled at fixed rate (e.g., 10/sec). Each request consumes one token. Empty bucket = 429. Supports bursts: unused tokens accumulate up to capacity. Most popular — used by Kong, AWS, Stripe, GitHub. Parameters: capacity (burst) + refill rate."},{"heading":"Fixed vs Sliding Window","text":"Fixed Window: count in wall-clock intervals. Simple but edge bursts at boundaries. Sliding Window Log: track timestamps. Precise but memory-intensive. Sliding Window Counter: sub-windows. Good balance of precision and memory."},{"heading":"Distributed Rate Limiting","text":"Single server: in-memory (fast, lost on restart). Redis: atomic INCR+EXPIRE for distributed counting. Lua scripting for atomic token bucket. Consistent hashing: route same client to same server. Redis: ~10-50us per check."},{"heading":"Rate Limiting Strategies","text":"Hard: strict limit, 429 immediately. Soft: allow bursts. Elastic: bursts with delay (queue). Tiered: Free (10 rpm), Pro (100 rpm), Enterprise (10k rpm). Concurrency limiting: max simultaneous requests."}],"interviewAnswer":"Rate limiting is essential for API production. Use Redis-based sliding window for distributed systems. Set informative headers. Return 429 with Retry-After. Choose algorithm: Token Bucket for bursty traffic, Sliding Window for precise limits. Always fail open if limiter fails.","interviewQuestions":[{"question":"What is rate limiting?","answer":"Controlling requests per time window to prevent abuse and ensure fair usage."},{"question":"What HTTP status for rate limiting?","answer":"429 Too Many Requests with Retry-After header."},{"question":"Common algorithms?","answer":"Token Bucket, Leaky Bucket, Fixed Window, Sliding Window Log, Sliding Window Counter."},{"question":"What is Token Bucket?","answer":"Bucket holds N tokens, filled at fixed rate. Each request consumes a token. Supports bursts."},{"question":"Fixed vs Sliding Window?","answer":"Fixed: simple but edge bursts. Sliding: more precise at boundaries."},{"question":"Best distributed storage?","answer":"Redis with atomic INCR/EXPIRE and Lua scripts."},{"question":"Rate limit headers?","answer":"X-RateLimit-Limit, X-RateLimit-Remaining, X-RateLimit-Reset, Retry-After."},{"question":"Concurrency vs rate limiting?","answer":"Rate: requests per time. Concurrency: max simultaneous requests."},{"question":"What is a usage quota?","answer":"Cumulative limit over longer period (e.g., 10k/month)."},{"question":"Fail open or closed?","answer":"Fail open if the rate limiter is down."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Rate Limiting</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Client</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Sends request</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"200\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Rate Limiter</text><text x=\"200\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Check limit</text><line x1=\"150\" y1=\"60\" x2=\"150\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"250\" y1=\"48\" x2=\"280\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Allowed</text><text x=\"60\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Process</text><rect x=\"160\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"210\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Denied</text><text x=\"210\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">429 Too Many</text><rect x=\"10\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Token Bucket</text><text x=\"60\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Refill+capacity</text><rect x=\"10\" y=\"140\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"60\" y=\"156\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Redis</text><text x=\"60\" y=\"168\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Distributed</text><rect x=\"160\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"210\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Headers</text><text x=\"210\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Limit,Remaining,Reset</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Rate Limiting</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Token Bucket/Sliding Window. Redis-based. 429+Retry-After.</text></svg>","codeExamples":"<text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Rate Limiting: Control request rates. Token Bucket/Sliding Window. 429 with Retry-After.</text>","mcqQuestions":[{"title":"Token Bucket (Node.js+Redis)","useCase":"Distributed token bucket.","code":"class TokenBucket{\n  constructor(redis,key,capacity,refillRate){\n    this.redis=redis;this.key=key;this.capacity=capacity;this.refillRate=refillRate;\n  }\n  async tryConsume(count){\n    const script=`local k=KEYS[1] local cap=tonumber(ARGV[1])\n      local rate=tonumber(ARGV[2]) local now=redis.call(\"TIME\")[1] local cost=tonumber(ARGV[3])\n      local b=redis.call(\"HMGET\",k,\"tokens\",\"lastRefill\")\n      local t=tonumber(b[1])or cap local lr=tonumber(b[2])or now\n      local elapsed=math.max(0,now-lr)\n      t=math.min(cap,t+elapsed*rate)\n      if t>=cost then\n        redis.call(\"HSET\",k,\"tokens\",t-cost,\"lastRefill\",now)\n        redis.call(\"EXPIRE\",k,math.ceil(cap/rate)+1)\n        return{1,t-cost}\n      else return{0,t} end`;\n    const r=await this.redis.eval(script,1,this.key,this.capacity,this.refillRate,count);\n    return{allowed:r[1],remaining:r[2]};\n  }\n}","description":"Distributed Token Bucket with Redis Lua atomicity."},{"title":"Rate Limiting Middleware (Express)","useCase":"Sliding window with Redis.","code":"const rateLimit=require(\"express-rate-limit\");\nconst RedisStore=require(\"rate-limit-redis\");\nconst limiter=rateLimit({\n  windowMs:60*1000,max:100,\n  standardHeaders:true,\n  store:new RedisStore({sendCommand:(...a)=>redis.sendCommand(a)}),\n  handler:(req,res)=>{res.status(429).json({error:\"Too many requests\"})}\n});\napp.use(\"/api/\",limiter);","description":"Express rate limiting with Redis store."},{"title":"In-Memory Token Bucket","useCase":"Single-server implementation.","code":"class MemoryTokenBucket{\n  constructor(capacity,refillRate){\n    this.capacity=capacity;this.refillRate=refillRate;this.buckets=new Map();\n  }\n  consume(key,count){\n    const now=Date.now();let b=this.buckets.get(key);\n    if(!b){b={tokens:this.capacity,lastRefill:now};this.buckets.set(key,b);}\n    const elapsed=(now-b.lastRefill)/1000;\n    b.tokens=Math.min(this.capacity,b.tokens+elapsed*this.refillRate);b.lastRefill=now;\n    if(b.tokens>=count){b.tokens-=count;return true;}\n    return false;\n  }\n}","description":"In-memory token bucket for single-server."},{"title":"Rate Limit Headers and Response","useCase":"Standard headers.","code":"class RateLimiterResponse{\n  static addHeaders(res,limit,remaining,reset){\n    res.setHeader(\"X-RateLimit-Limit\",limit);\n    res.setHeader(\"X-RateLimit-Remaining\",remaining);\n    res.setHeader(\"X-RateLimit-Reset\",Math.ceil(reset/1000));\n  }\n  static onLimitExceeded(res,retryAfterMs){\n    res.setHeader(\"Retry-After\",Math.ceil(retryAfterMs/1000));\n    res.status(429).json({error:\"Rate limit exceeded\"});\n  }\n}\nasync function rateLimitMW(req,res,next){\n  const key=req.ip||req.headers[\"x-api-key\"];\n  const result=await limiter.consume(key);\n  RateLimiterResponse.addHeaders(res,100,result.remaining,result.reset);\n  if(!result.allowed) return RateLimiterResponse.onLimitExceeded(res,result.retryAfter);\n  next();\n}","description":"Standard rate limit headers and 429 response."},{"title":"Tiered Rate Limiting","useCase":"Per-tier limits.","code":"const TIER_LIMITS={\n  free:{windowMs:60000,max:10},\n  basic:{windowMs:60000,max:100},\n  pro:{windowMs:60000,max:1000},\n  enterprise:{windowMs:60000,max:10000},\n};\nconst tieredLimiter=(req,res,next)=>{\n  const tier=req.user?.tier||\"free\";\n  const config=TIER_LIMITS[tier]||TIER_LIMITS.free;\n  const current=cache.get(key)||0;\n  if(current>=config.max) return res.status(429).json({error:\"Rate limit exceeded\",tier});\n  cache.set(key,current+1,config.windowMs/1000);next();\n};","description":"Tiered rate limiting for free/basic/pro/enterprise."},{"question":"Rate Limiting — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Rate Limiting — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Rate Limiting — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Rate Limiting — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Rate Limiting — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["api-gateway"]["ag-authentication"] = {"id":"ag-authentication","title":"Authentication","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Authentication (AuthN) in API Gateways verifies the identity of clients making API requests before they reach backend services.","Common methods: API Keys (simple), JWT Bearer Tokens (stateless), OAuth2/OIDC (delegated), Basic Auth (legacy), mTLS (mutual TLS).","API Gateways centralize authentication — implement once instead of duplicating in every microservice.","Gateway validates auth, extracts identity claims, forwards as headers (X-User-ID, X-User-Role) to backends."],"laymanDefinition":"API Gateway authentication is like a single security checkpoint at a corporate building entrance. Instead of each office checking ID separately, the main entrance checks your badge, stamps your hand (headers) with your role. Every office sees you are authorized without rechecking.","deepDive":[{"heading":"API Key Authentication","text":"Simplest: client includes key in header (X-API-Key), query param, or body. Gateway checks against stored keys. Keys are long-lived and static. Good for server-to-server, service accounts, developer portals. Less secure than tokens — rotate periodically."},{"heading":"JWT Bearer Token Auth","text":"Client presents JWT in Authorization: Bearer header. Gateway validates signature (HS256/RS256/ES256), expiration (exp), audience (aud), issuer (iss). Extracts claims (sub, role) into headers. Stateless — no DB lookup. JWKS for key rotation."},{"heading":"OAuth2 / OIDC Auth","text":"Gateway acts as OAuth2 resource server. Authorization Code flow: redirect to auth server, exchange code for tokens. Client Credentials: server-to-server. OIDC: adds ID token for user identity. Gateway validates access tokens, optionally introspects."},{"heading":"mTLS (Mutual TLS)","text":"Both client and server present TLS certificates. Gateway validates client cert against trusted CA. Extracts identity from CN/SAN fields. No tokens needed. Strongest auth — used in zero-trust, financial APIs, IoT."}],"interviewAnswer":"Centralize authentication at the API Gateway. Choose method by client type: API Keys for services, JWT for web/mobile, OAuth2 for delegated, mTLS for high-security. Forward identity claims as headers. Implement token introspection for opaque tokens.","interviewQuestions":[{"question":"What is authentication in API Gateway?","answer":"Verifying API client identity at the gateway before requests reach backend services."},{"question":"Common API Gateway auth methods?","answer":"API Keys, JWT Bearer, OAuth2/OIDC, Basic Auth, mTLS."},{"question":"Why centralize authentication?","answer":"Single implementation, consistent security, no per-service auth logic, simplified audit."},{"question":"What does JWT validation check?","answer":"Signature, expiration (exp), audience (aud), issuer (iss), and optionally other claims."},{"question":"How does gateway communicate identity to backends?","answer":"Forwarding claims as HTTP headers: X-User-ID, X-User-Role."},{"question":"What is mTLS?","answer":"Mutual TLS — both client and server present certificates for mutual authentication."},{"question":"Difference between API Keys and JWT?","answer":"API Keys: static, long-lived. JWT: dynamic, short-lived, contains claims."},{"question":"How does OAuth2 work with gateways?","answer":"Gateway validates access tokens, optionally introspects, forwards user context."},{"question":"What is token introspection?","answer":"OAuth2 standard (RFC 7662) for validating opaque tokens via auth server."},{"question":"What should gateway do with invalid tokens?","answer":"Return 401 Unauthorized immediately, without forwarding to backend."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Authentication</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Client</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Request+Creds</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"200\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">API Gateway</text><text x=\"200\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Validates AuthN</text><line x1=\"250\" y1=\"48\" x2=\"280\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"150\" y1=\"60\" x2=\"150\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">API Key</text><text x=\"60\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Static lookup</text><rect x=\"10\" y=\"100\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"116\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">JWT</text><text x=\"60\" y=\"128\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Signature+claims</text><rect x=\"10\" y=\"130\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"146\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">OAuth2</text><text x=\"60\" y=\"158\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Token validation</text><rect x=\"10\" y=\"160\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"60\" y=\"176\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">mTLS</text><text x=\"60\" y=\"188\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Certificate</text><rect x=\"160\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"210\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Backend</text><text x=\"210\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Receives user headers</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">API Gateway Auth</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Centralized: API Keys, JWT, OAuth2, mTLS. Forward identity as headers.</text></svg>","codeExamples":"<text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Authentication: API Gateway verifies identity. Methods: API Keys, JWT, OAuth2, mTLS.</text>","mcqQuestions":[{"title":"JWT Validation Middleware","useCase":"Validate JWT and extract claims.","code":"const jwt=require(\"jsonwebtoken\");\nasync function authenticateGateway(req,res,next){\n  const auth=req.headers.authorization;\n  if(!auth?.startsWith(\"Bearer \")) return res.status(401).json({error:\"Missing auth\"});\n  const token=auth.split(\" \")[1];\n  try{\n    const decoded=jwt.verify(token,process.env.JWT_SECRET,{algorithms:[\"RS256\"],audience:\"api-gateway\"});\n    req.headers[\"X-User-ID\"]=decoded.sub;\n    req.headers[\"X-User-Role\"]=decoded.role;\n    delete req.headers.authorization;\n    next();\n  }catch(e){res.status(401).json({error:\"Invalid token\"})}\n}","description":"Gateway JWT validation forwarding claims as headers."},{"title":"API Key Authentication","useCase":"Simple key-based auth.","code":"async function authenticateApiKey(req,res,next){\n  const key=req.headers[\"x-api-key\"]||req.query.api_key;\n  if(!key) return res.status(401).json({error:\"API key required\"});\n  const hash=crypto.createHash(\"sha256\").update(key).digest(\"hex\");\n  const client=await redis.hgetall(\"apikey:\"+hash);\n  if(!client) return res.status(401).json({error:\"Invalid key\"});\n  req.headers[\"X-Client-ID\"]=client.id;\n  req.headers[\"X-Client-Tier\"]=client.tier;\n  next();\n}","description":"API key auth with Redis-backed key store."},{"title":"OAuth2 Token Introspection","useCase":"Validate opaque tokens.","code":"async function introspectToken(token){\n  const r=await fetch(\"https://auth.example.com/introspect\",{method:\"POST\",\n    headers:{\"Content-Type\":\"application/x-www-form-urlencoded\",\"Authorization\":\"Basic \"+Buffer.from(clientId+\":\"+clientSecret).toString(\"base64\")},\n    body:new URLSearchParams({token})});\n  const data=await r.json();\n  if(!data.active) throw new Error(\"Token inactive\");\n  return {sub:data.sub,scope:data.scope,clientId:data.client_id,exp:data.exp};\n}","description":"OAuth2 token introspection for opaque access tokens."},{"title":"mTLS Authentication","useCase":"Mutual TLS.","code":"const https=require(\"https\");const fs=require(\"fs\");\nconst options={\n  key:fs.readFileSync(\"server.key\"),\n  cert:fs.readFileSync(\"server.crt\"),\n  requestCert:true,rejectUnauthorized:true,\n  ca:fs.readFileSync(\"client-ca.crt\"),\n};\nhttps.createServer(options,(req,res)=>{\n  const cert=req.socket.getPeerCertificate();\n  req.headers[\"X-Client-CN\"]=cert.subject?.CN;\n  req.headers[\"X-Client-Fingerprint\"]=cert.fingerprint;\n}).listen(443);","description":"mTLS with client certificate validation and identity extraction."},{"title":"JWKS Key Rotation","useCase":"Rotate keys without downtime.","code":"let cachedKeys=null;let lastFetch=0;\nasync function getJwksKeys(){\n  if(cachedKeys&&Date.now()-lastFetch<3600000) return cachedKeys;\n  const r=await fetch(\"https://auth.example.com/.well-known/jwks.json\");\n  const jwks=await r.json();\n  cachedKeys=jwks.keys.map(k=>({kid:k.kid,publicKey:jwktopem(k),alg:k.alg}));\n  lastFetch=Date.now();return cachedKeys;\n}\nasync function authenticateWithJwks(req,res,next){\n  const token=extractToken(req);\n  const decoded=jwt.decode(token,{complete:true});\n  const kid=decoded?.header?.kid;\n  const keys=await getJwksKeys();\n  const key=keys.find(k=>k.kid===kid);\n  if(!key) return res.status(401).json({error:\"Unknown key ID\"});\n  jwt.verify(token,key.publicKey,{algorithms:[key.alg]});\n  next();\n}","description":"JWKS key rotation with cached public key discovery."},{"question":"Authentication — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Authentication — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Authentication — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Authentication — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Authentication — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["api-gateway"]["ag-authorization"] = {"id":"ag-authorization","title":"Authorization","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Authorization (AuthZ) in API Gateways controls what authenticated users can access � endpoints, operations, and data.","Authorization happens AFTER authentication: first verify who you are, then check what you can access.","Common models: RBAC (Role-Based), ABAC (Attribute-Based), PBAC (Policy-Based), ReBAC (Relationship-Based).","Gateways enforce authorization at entry: allowed HTTP methods, paths, resource ownership, request validation."],"laymanDefinition":"Authorization at the API Gateway is like a building badge system. After front door checks your ID (authN), elevator only lights buttons for floors you can visit.","deepDive":[{"heading":"Enforcing Authorization at Gateway","text":"Route-level: which paths/methods a role can access. Claim-checking: validate JWT claims against endpoint requirements. Policy-based: external engine (OPA, Casbin). Backend should also enforce (defense in depth)."},{"heading":"RBAC with API Gateway","text":"Roles have permissions. Gateway checks role from JWT claim (X-User-Role) against route permissions. Example: admin can DELETE /users, user only GET /users/me. 403 Forbidden."},{"heading":"ABAC with API Gateway","text":"Policy evaluates user attributes (role, dept), resource attributes (type, owner), environment (time, location). Gateway invokes OPA sidecar. More flexible than RBAC."},{"heading":"AuthZ Flow Through Gateway","text":"1. Client sends request with token. 2. Gateway authenticates. 3. Gateway checks authorization. 4. If allowed, forward with identity headers. 5. Backend performs additional fine-grained checks."}],"interviewAnswer":"Gateway authorization is first line of defense, not only one. Coarse-grained at gateway. Fine-grained at service layer. RBAC for simple, ABAC/OPA for complex. 403 for unauthorized.","interviewQuestions":[{"question":"What is authorization in API Gateway?","answer":"Controlling what authenticated users can access � endpoints, methods, and resources."},{"question":"Difference between authN and authZ?","answer":"AuthN: who you are. AuthZ: what you can do. AuthN first."},{"question":"HTTP status for authorization failure?","answer":"403 Forbidden."},{"question":"What is RBAC?","answer":"Role-Based Access Control � roles have permissions, users assigned to roles."},{"question":"What is ABAC?","answer":"Attribute-Based Access Control � decisions based on user, resource, environment attributes."},{"question":"What is OPA?","answer":"Open Policy Agent � open-source policy engine for unified authorization."},{"question":"Should gateway be the only authZ layer?","answer":"No � defense in depth: gateway coarse, service fine-grained, DB RLS."},{"question":"Principle of least privilege?","answer":"Minimum permissions necessary."},{"question":"401 vs 403?","answer":"401: not authenticated. 403: authenticated but not authorized."},{"question":"How does gateway enforce authZ?","answer":"Check JWT claims (role, permissions) against endpoint requirements."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Authorization</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Client</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">AuthZ request</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"200\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">API Gateway</text><text x=\"200\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Check AuthZ</text><line x1=\"150\" y1=\"60\" x2=\"150\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"250\" y1=\"48\" x2=\"280\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Allowed</text><text x=\"60\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Forward</text><rect x=\"160\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"210\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Denied</text><text x=\"210\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">403 Forbidden</text><rect x=\"10\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">RBAC</text><text x=\"60\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Role check</text><rect x=\"10\" y=\"140\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"60\" y=\"156\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">ABAC/OPA</text><text x=\"60\" y=\"168\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Policy engine</text><rect x=\"160\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"210\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Backend</text><text x=\"210\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fine-grained</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Authorization</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Access control: RBAC, ABAC, OPA. Gateway+service defense in depth. 403.</text></svg>","codeExamples":"<text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Authorization: Controlling access after authN. RBAC, ABAC, OPA. 403 for denied.</text>","mcqQuestions":[{"title":"RBAC Middleware in Gateway","useCase":"Role-based protection.","code":"const PERMISSIONS={\n  \"/api/users\":{GET:[\"admin\",\"manager\",\"user\"],POST:[\"admin\"],DELETE:[\"admin\"]},\n  \"/api/orders\":{GET:[\"admin\",\"manager\",\"user\"],POST:[\"admin\",\"manager\"]},\n  \"/api/reports\":{GET:[\"admin\",\"manager\"]},\n};\nfunction authorize(req,res,next){\n  const role=req.headers[\"x-user-role\"];\n  const perm=PERMISSIONS[req.path];\n  if(!perm) return next();\n  if(!perm[req.method]?.includes(role)) return res.status(403).json({error:\"Insufficient permissions\"});\n  next();\n}","description":"RBAC middleware checking role against endpoint permissions."},{"title":"OPA Authorization","useCase":"External policy engine.","code":"# OPA policy (Rego)\npackage api.authz\ndefault allow = false\nallow { input.method==\"GET\" input.path==\"/api/users\" input.user.role==\"admin\" }\nallow { input.method==\"GET\" input.path==\"/api/orders\" input.user.role in [\"admin\",\"manager\",\"user\"] }\nallow { input.method==\"DELETE\" startswith(input.path,\"/api/users/\") input.user.id==split(input.path,\"/\")[3] }\n// Gateway calls OPA:\nasync function checkOpaPolicy(req){\n  const input={method:req.method,path:req.path,user:{id:req.headers[\"x-user-id\"],role:req.headers[\"x-user-role\"]}};\n  const r=await fetch(\"http://opa:8181/v1/data/api/authz\",{method:\"POST\",body:JSON.stringify({input})});\n  const d=await r.json();return d.result;\n}","description":"OPA for externalized fine-grained authorization."},{"title":"Casbin Authorization","useCase":"Library-based enforcement.","code":"# model.conf: r = sub, obj, act\n# policy.csv:\np, admin, /api/*, (GET)|(POST)|(PUT)|(DELETE)\np, manager, /api/orders/*, (GET)|(POST)|(PUT)\np, user, /api/orders/*, GET\ng, alice, admin\n// Node.js: const allowed = await enforcer.enforce(\"alice\", \"/api/users\", \"DELETE\");","description":"Casbin with ACL/RBAC via model and policy files."},{"question":"Authorization — What is important for security?","options":["Access control and encryption","Open access","Shared passwords","No auditing"],"answer":0,"explanation":"Access control and encryption are fundamental security measures."},{"question":"Authorization — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Authorization — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Authorization — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Authorization — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Authorization — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Authorization — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["api-gateway"]["ag-api-keys"] = {"id":"ag-api-keys","title":"API Keys","difficulty":"beginner","estimatedMinutes":10,"tldr":["API Keys are long-lived, static credentials identifying and authenticating API clients for machine-to-machine communication.","Passed in headers (X-API-Key), query params, or body. Identify the client, NOT a specific user.","Best practices: hash before storing, support rotation, allow multiple keys per client, set expiration, log usage, revoke.","Use for: service accounts, third-party integrations, developer portals, public API tiers."],"laymanDefinition":"API Keys are like apartment building mailbox keys. Each service gets a specific key. Lost key = get new one, old one stops working.","deepDive":[{"heading":"API Key Generation","text":"crypto.randomBytes(32).toString(\"hex\") = 64-char hex. Prefix: sk_live_abc123. Store SHA-256 hash only. Rotate 90-365 days."},{"heading":"API Key Validation in Gateway","text":"Extract key, hash it, look up in DB/Redis. Check valid/expired/revoked/scopes. Rate limit by tier. Cache in Redis (short TTL)."},{"heading":"API Key vs JWT","text":"API Key: static, long-lived, identifies client, hash lookup. JWT: dynamic, short-lived, user claims, stateless. Many systems use both."},{"heading":"API Key Management","text":"Create: generate, hash, store, return once. List: show prefixes only. Revoke: delete/flag hash. Rotate: new key, old grace period."}],"interviewAnswer":"Essential for machine-to-machine API access. Generate with crypto randomness, hash before storing, never expose in logs. Support rotation with grace period. Use prefixes. Combine with per-key rate limiting.","interviewQuestions":[{"question":"What is an API Key?","answer":"Long-lived, static credential identifying API clients for machine-to-machine communication."},{"question":"How should API Keys be stored?","answer":"Hashed (SHA-256). Return plaintext once at creation."},{"question":"What header for API Keys?","answer":"X-API-Key header, also query param or body."},{"question":"API Key vs JWT?","answer":"API Key: static, identifies client. JWT: dynamic, carries user identity."},{"question":"How to revoke?","answer":"Delete or flag the hashed key."},{"question":"What is key rotation?","answer":"Replacing old key with new. Grace period where both work."},{"question":"Can API Keys identify a user?","answer":"No � they identify applications."},{"question":"Recommended format?","answer":"Prefix + type + random: sk_live_abc123def456."},{"question":"Should API Keys expire?","answer":"Yes. Rotate periodically."},{"question":"What to log?","answer":"Key prefix, endpoint, timestamp, IP, success/failure."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">API Keys</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Client</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">App/Service</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"200\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">API Gateway</text><text x=\"200\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Validate Key</text><line x1=\"150\" y1=\"60\" x2=\"150\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"250\" y1=\"48\" x2=\"280\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">X-API-Key</text><text x=\"60\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Header/Query</text><rect x=\"10\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Hash Lookup</text><text x=\"60\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">SHA-256</text><rect x=\"10\" y=\"140\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"156\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Redis Cache</text><text x=\"60\" y=\"168\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fast</text><rect x=\"160\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"210\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Rate Limit</text><text x=\"210\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Per-key</text><rect x=\"160\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"210\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Backend</text><text x=\"210\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Processing</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">API Keys</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Static credentials. Hash, rotate, rate-limit. Machine-to-machine auth.</text></svg>","codeExamples":"<text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">API Keys: Simple static credentials for service-to-service auth. Hash, rotate, rate-limit.</text>","mcqQuestions":[{"title":"API Key Generation and Storage","useCase":"Generate and hash keys.","code":"const crypto=require(\"crypto\");\nfunction generateApiKey(clientId,type=\"live\"){\n  const random=crypto.randomBytes(32).toString(\"hex\");\n  const apiKey=\"sk_\"+type+\"_\"+random;\n  const hash=crypto.createHash(\"sha256\").update(apiKey).digest(\"hex\");\n  return{plaintext:apiKey,hash,prefix:apiKey.substring(0,12)};\n}\nasync function storeApiKey(clientId,keyData){\n  await db.query(\"INSERT INTO api_keys (client_id,key_hash,key_prefix,expires_at) VALUES (,,,NOW()+INTERVAL '365 days')\",[clientId,keyData.hash,keyData.prefix]);\n}","description":"API key generation with crypto randomness and hashing."},{"title":"API Key Validation Middleware","useCase":"Validate at gateway.","code":"async function apiKeyAuth(req,res,next){\n  const key=req.headers[\"x-api-key\"]||req.query.api_key;\n  if(!key) return res.status(401).json({error:\"API key required\"});\n  const hash=crypto.createHash(\"sha256\").update(key).digest(\"hex\");\n  let client=await redis.hgetall(\"apikey:\"+hash);\n  if(!client){\n    const r=await db.query(\"SELECT * FROM api_keys WHERE key_hash= AND (expires_at IS NULL OR expires_at>NOW()) AND revoked=false\",[hash]);\n    client=r.rows[0];\n    if(!client) return res.status(401).json({error:\"Invalid key\"});\n    await redis.hset(\"apikey:\"+hash,{client_id:client.client_id,tier:client.tier});\n    await redis.expire(\"apikey:\"+hash,300);\n  }\n  req.client=client;next();\n}","description":"API key validation with Redis cache and DB fallback."},{"title":"Key Rotation with Grace Period","useCase":"Rotate without downtime.","code":"async function rotateApiKey(clientId,oldKey){\n  const oldHash=crypto.createHash(\"sha256\").update(oldKey).digest(\"hex\");\n  const existing=await db.query(\"SELECT * FROM api_keys WHERE key_hash= AND client_id=\",[oldHash,clientId]);\n  if(!existing.rows[0]) throw new Error(\"Invalid old key\");\n  const newKey=generateApiKey(clientId);\n  await storeApiKey(clientId,newKey);\n  await db.query(\"UPDATE api_keys SET expires_at=NOW()+INTERVAL '7 days' WHERE key_hash=\",[oldHash]);\n  return{newKey:newKey.plaintext,gracePeriodDays:7};\n}","description":"Key rotation with 7-day grace period."},{"title":"Per-Key Rate Limiting","useCase":"Rate limit by key tier.","code":"const TIER_LIMITS={free:{rpm:10},basic:{rpm:100},pro:{rpm:1000},enterprise:{rpm:10000}};\nasync function perKeyRateLimit(req,res,next){\n  const key=req.headers[\"x-api-key\"];\n  const hash=crypto.createHash(\"sha256\").update(key).digest(\"hex\");\n  const client=await getClientByKeyHash(hash);\n  const limits=TIER_LIMITS[client.tier]||TIER_LIMITS.free;\n  const current=await redis.incr(\"ratelimit:\"+hash+\":minute\");\n  if(current===1) await redis.expire(\"ratelimit:\"+hash+\":minute\",60);\n  if(current>limits.rpm) return res.status(429).json({error:\"Rate limited\",tier:client.tier});\n  res.setHeader(\"X-RateLimit-Limit\",limits.rpm);res.setHeader(\"X-RateLimit-Remaining\",limits.rpm-current);\n  next();\n}","description":"Per-API-key rate limiting with tier-based limits."},{"question":"API Keys — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"API Keys — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"API Keys — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"API Keys — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"API Keys — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"API Keys — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["api-gateway"]["ag-jwt-validation"] = {"id":"ag-jwt-validation","title":"JWT Validation","difficulty":"intermediate","estimatedMinutes":18,"tldr":["JWT (JSON Web Token) is a compact, self-contained token format for transmitting claims between parties, commonly used for API authentication.","Three parts: Header (alg, typ), Payload (claims), Signature (HMAC or RSA/ECDSA). Base64url encoded, dot-separated.","Gateway validates: signature (trusted public key), expiration (exp), not before (nbf), issuer (iss), audience (aud).","Best practices: short expiry (15-60min), use RS256/ES256 over HS256, rotate signing keys, blacklist for immediate revocation."],"laymanDefinition":"JWT is like a concert wristband. Has your VIP status, expiry time, and venue. Wristband is signed � can check but not forge. Sold separately with hologram (real one).","deepDive":[{"heading":"JWT Structure","text":"Header: {\"alg\":\"RS256\",\"typ\":\"JWT\"}. Payload: {\"sub\":\"user123\",\"role\":\"admin\",\"exp\":1748567890}. Signature: RSA-SHA256(base64urlEncode(header)+\".\"+base64urlEncode(payload), privateKey)."},{"heading":"Signature Verification at Gateway","text":"Fetch JWKS (JSON Web Key Set) from auth server. Cache keys with kid (key ID) matching. Verify: decode using jwks-rsa+jsonwebtoken. Check: signature, exp, nbf, iss, aud. Reject expired."},{"heading":"Token Revolution Strategies","text":"JWT cannot be revoked by expiry alone. Solutions: short TTL (15min), token blacklist (Redis), token version DB, refresh tokens. Do not validate remote on every call."},{"heading":"JWKS (JSON Web Key Set)","text":"Standard endpoint: /.well-known/jwks.json. Contains public keys (modulus n, exponent e for RSA). Gateway caches, rotates automatically. Allows key rotation without downtime."}],"interviewAnswer":"JWT validation at gateway is critical: verify signature with JWKS, check claims (exp, nbf, iss, aud), handle revocation (blacklist/short TTL). Prefer RS256 for asymmetric signing. Rotate keys via JWKS. Reject on first failure.","interviewQuestions":[{"question":"What does JWT stand for?","answer":"JSON Web Token."},{"question":"JWT parts?","answer":"Header.Payload.Signature � three base64url-encoded segments."},{"question":"What is the exp claim?","answer":"Expiration time (Unix timestamp). Must be in the future."},{"question":"HS256 vs RS256?","answer":"HS256: symmetric (shared secret). RS256: asymmetric (RSA private/public). RS256 preferred."},{"question":"What is JWKS?","answer":"JSON Web Key Set � endpoint with public keys for verification."},{"question":"How to revoke JWT?","answer":"Short TTL + token blacklist (Redis). Refresh tokens for long sessions."},{"question":"What is kid?","answer":"Key ID in JWT header � matches JWKS key for rotation."},{"question":"Should JWT be blacklisted immediately on logout?","answer":"Yes � blacklist with TTL matching token expiry."},{"question":"What claims to validate?","answer":"Signature, exp, nbf, iss, aud, optionally sub."},{"question":"What is refresh token?","answer":"Long-lived token to get new access tokens. Stored securely."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">JWT Validation</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Client</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Request+JWT</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"200\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">API Gateway</text><text x=\"200\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Validate JWT</text><line x1=\"150\" y1=\"60\" x2=\"150\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"250\" y1=\"48\" x2=\"280\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">JWKS</text><text x=\"60\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cache keys</text><rect x=\"10\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Signature</text><text x=\"60\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Verify RSA</text><rect x=\"10\" y=\"140\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"156\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Claims</text><text x=\"60\" y=\"168\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">exp/iss/aud</text><rect x=\"160\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"210\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Blacklist</text><text x=\"210\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Redis check</text><rect x=\"160\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"210\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Backend</text><text x=\"210\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">User context</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">JWT</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Self-contained token. RS256. JWKS. Short TTL. Blacklist for revocation.</text></svg>","codeExamples":"<text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">JWT: Self-contained auth tokens with signature, expiry, claims. Validate signature and claims at gateway.</text>","mcqQuestions":[{"title":"JWT Verification with JWKS","useCase":"Verify using public keys.","code":"const jwt=require(\"jsonwebtoken\");\nconst jwksClient=require(\"jwks-rsa\");\nconst client=jwksClient({jwksUri:\"https://auth.example.com/.well-known/jwks.json\"});\nfunction getKey(header,callback){\n  client.getSigningKey(header.kid,(err,key)=>{\n    if(err) return callback(err);\n    const signingKey=key.getPublicKey();\n    callback(null,signingKey);\n  });\n}\nasync function validateJwt(req,res,next){\n  const token=req.headers.authorization?.replace(\"Bearer \",\"\");\n  if(!token) return res.status(401).json({error:\"Token required\"});\n  jwt.verify(token,getKey,{algorithms:[\"RS256\"],issuer:\"https://auth.example.com\",audience:\"https://api.example.com\"},err=>{\n    if(err) return res.status(401).json({error:\"Invalid token\",details:err.message});\n    const decoded=jwt.decode(token);\n    req.user=decoded;next();\n  });\n}","description":"JWT verification with JWKS-fetched public keys and claim validation."},{"title":"Token Blacklist","useCase":"Revoke tokens before expiry.","code":"async function blacklistToken(jti,exp){\n  const ttl=Math.max(0,exp-Math.floor(Date.now()/1000));\n  await redis.set(\"blacklist:\"+jti,\"true\",\"EX\",ttl);\n}\nasync function checkBlacklist(token){\n  const decoded=jwt.decode(token);\n  if(!decoded) return true;\n  const blocked=await redis.exists(\"blacklist:\"+decoded.jti);\n  return blocked===1;\n}\nasync function validateWithBlacklist(req,res,next){\n  const token=req.headers.authorization?.replace(\"Bearer \",\"\");\n  const blacklisted=await checkBlacklist(token);\n  if(blacklisted) return res.status(401).json({error:\"Token revoked\"});next();\n}","description":"Token blacklist using JTI (JWT ID) with TTL matching expiry."},{"title":"Refresh Token Flow","useCase":"Access + refresh tokens.","code":"// Login returns both\nasync function login(req,res){\n  const accessToken=jwt.sign({sub:user.id,role:user.role},privateKey,\n    {algorithm:\"RS256\",expiresIn:\"15m\",issuer:\"https://auth.example.com\",audience:\"https://api.example.com\"});\n  const refreshToken=crypto.randomBytes(64).toString(\"hex\");\n  await db.query(\"INSERT INTO refresh_tokens (user_id,token_hash,expires_at) VALUES (,SHA256(),NOW()+INTERVAL '7 days')\",[user.id,refreshToken]);\n  res.json({access_token:accessToken,refresh_token:refreshToken,expires_in:900});\n}","description":"Refresh token flow: short-lived access token + long-lived refresh token."},{"title":"HS256 vs RS256","useCase":"Symmetric vs asymmetric.","code":"// HS256: Shared secret (symmetric)\nconst token=jwt.sign({sub:\"123\"},HS256_SECRET,{algorithm:\"HS256\",expiresIn:\"15m\"});\nconst decoded=jwt.verify(token,HS256_SECRET); // Same secret on all services\n// RS256: Private/public key pair (asymmetric)\nconst token=jwt.sign({sub:\"123\"},privateKey,{algorithm:\"RS256\"});\nconst decoded=jwt.verify(token,publicKey); // Only auth server has private key","description":"HS256 shared secret vs RS256 asymmetric. RS256 preferred for microservices."},{"question":"JWT Validation — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"JWT Validation — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"JWT Validation — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"JWT Validation — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"JWT Validation — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"JWT Validation — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["api-gateway"]["ag-oauth"] = {"id":"ag-oauth","title":"OAuth","difficulty":"advanced","estimatedMinutes":20,"tldr":["OAuth 2.0 is the industry-standard authorization framework enabling third-party applications to access resources without sharing credentials.","Four actors: Resource Owner (user), Client (app), Authorization Server (Auth0/Keycloak), Resource Server (API).","Grant types: Authorization Code (web apps), PKCE (SPA/mobile), Client Credentials (M2M), Implicit (deprecated), Device Code, Refresh Token.","Gateway acts as Resource Server: validates access tokens, forwards identity to downstream services, enforces scopes."],"laymanDefinition":"OAuth 2.0 is like a hotel valet key system. You (user) give receptionist (auth server) a limited key that valets (apps) can use for specific things (scopes). Valets cannot access rooms, only parking.","deepDive":[{"heading":"OAuth Grant Types","text":"Auth Code: user logs in auth server, gets code, exchanges for access token. PKCE: code challenge+verifier for SPAs. Client Credentials: no user, app-to-app. Refresh: get new tokens."},{"heading":"Gateway as Resource Server","text":"1. Client sends access token. 2. Gateway validates (introspect or verify locally). 3. Checks scopes match endpoint. 4. Forwards identity (X-User-Id, X-Scopes). 5. Backend trusts gateway headers."},{"heading":"OAuth with Multiple Providers","text":"Gateway can integrate with many IdPs (Auth0, Keycloak, custom). Discovery URL: /.well-known/openid-configuration. JWKS for public keys. Federation via OIDC."},{"heading":"Token Introspection vs Local Validation","text":"Local: fast, no network, needs JWKS. Introspection: real-time validation, detects revoked tokens immediately, RP call. Gateway caches introspection results short TTL."}],"interviewAnswer":"OAuth 2.0 is complex but critical. Use Authorization Code + PKCE for user-facing apps, Client Credentials for M2M. Gateway validates tokens and enforces scopes. Prefer local JWT validation with JWKS for performance; use introspection for high-value operations.","interviewQuestions":[{"question":"What is OAuth 2.0?","answer":"Authorization framework for delegated access without sharing credentials."},{"question":"Four OAuth actors?","answer":"Resource Owner, Client, Authorization Server, Resource Server."},{"question":"Grant type for SPAs?","answer":"Authorization Code with PKCE (Proof Key for Code Exchange)."},{"question":"Grant type for M2M?","answer":"Client Credentials Grant."},{"question":"What is scope?","answer":"Permission level for the token: read:orders, write:users."},{"question":"Token introspection?","answer":"Auth server endpoint to validate and check token status in real time."},{"question":"Local validation vs introspection?","answer":"Local: fast, cached JWKS, no network. Introspection: real-time, detects revocations."},{"question":"OpenID Connect?","answer":"Identity layer on top of OAuth 2.0 � adds ID token (JWT with user info)."},{"question":"What is OIDC discovery?","answer":"/.well-known/openid-configuration � auth server metadata."},{"question":"Why PKCE for SPAs?","answer":"Cannot store client_secret securely; PKCE uses code verifier+challenge."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">OAuth</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Client</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">App</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"200\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Auth Server</text><text x=\"200\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Login+Token</text><line x1=\"150\" y1=\"60\" x2=\"150\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"40\" y1=\"48\" x2=\"10\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Resource Owner</text><text x=\"60\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">User</text><line x1=\"110\" y1=\"82\" x2=\"140\" y2=\"82\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"200\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">API Gateway</text><text x=\"200\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Val. token</text><line x1=\"250\" y1=\"82\" x2=\"280\" y2=\"82\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Scopes</text><text x=\"60\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Enforce</text><rect x=\"160\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"210\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Backend</text><text x=\"210\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Identity</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">OAuth 2.0</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auth Code + PKCE. Client Credentials. Gateway validates tokens. Scopes.</text></svg>","codeExamples":"<text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">OAuth 2.0: Industry-standard delegated authorization. Grants: Auth Code+PKCE, Client Credentials. Gateway validates tokens and enforces scopes.</text>","mcqQuestions":[{"title":"OAuth Client Credentials Flow","useCase":"M2M authentication.","code":"// Client requests access token\nconst response=await fetch(\"https://auth.example.com/oauth/token\",{\n  method:\"POST\",\n  headers:{\"Content-Type\":\"application/x-www-form-urlencoded\"},\n  body:new URLSearchParams({\n    grant_type:\"client_credentials\",\n    client_id:\"service-a\",\n    client_secret:\"cs_abc123...\",\n    scope:\"read:orders write:orders\",\n  }),\n});\nconst {access_token}=await response.json();\n// Then use in API calls:\nfetch(\"https://api.example.com/orders\",{headers:{Authorization:\"Bearer \"+access_token}});","description":"Client Credentials Grant for M2M communication."},{"title":"Authorization Code with PKCE","useCase":"Secure SPA flow.","code":"// 1. Generate code verifier and challenge (SPA)\nconst verifier=crypto.randomBytes(32).toString(\"base64url\");\nconst challenge=crypto.createHash(\"sha256\").update(verifier).digest(\"base64url\");\n// 2. Redirect to auth server\nconst authUrl=\"https://auth.example.com/authorize?\"+new URLSearchParams({\n  response_type:\"code\",client_id:\"spa-client\",redirect_uri:\"https://app.example.com/callback\",\n  code_challenge:challenge,code_challenge_method:\"S256\",scope:\"openid profile email\",\n});\nwindow.location.href=authUrl;\n// 3. Exchange code (callback)\nconst tokenResponse=await fetch(\"https://auth.example.com/oauth/token\",{\n  method:\"POST\",\n  body:new URLSearchParams({grant_type:\"authorization_code\",code,code_verifier:verifier,redirect_uri:\"https://app.example.com/callback\",client_id:\"spa-client\"}),\n})","description":"PKCE flow for SPAs � code verifier ensures only the original app can exchange the code."},{"title":"Gateway Token Validation","useCase":"Validate at gateway.","code":"async function oauthGatewayMiddleware(req,res,next){\n  // Extract token from Authorization header or cookie\n  let token=req.cookies?.access_token||req.headers.authorization?.replace(\"Bearer \",\"\");\n  if(!token) return res.redirect(\"/login\");\n  // Validate locally or introspect\n  try{\n    const decoded=jwt.verify(token,getPublicKey,{algorithms:[\"RS256\"],issuer:\"https://auth.example.com\"});\n    req.user={id:decoded.sub,scopes:decoded.scope?.split(\" \")||[]};\n    next();\n  }catch(err){\n    // Token invalid/expired � try refresh\n    const refreshed=await refreshToken(req);\n    if(refreshed) return;\n    res.redirect(\"/login\");\n  }\n}\nfunction requireScope(scope){\n  return(req,res,next)=>{\n    if(!req.user?.scopes?.includes(scope)) return res.status(403).json({error:\"Insufficient scope\"});\n    next();\n  };\n}\n// Route: app.use(\"/api/orders\",requireToken,requireScope(\"read:orders\"),ordersRouter);","description":"Gateway validates OAuth tokens and enforces scopes with middleware."},{"title":"OAuth with Multiple Providers","useCase":"Federated OAuth.","code":"const PROVIDERS={\n  google:{discoveryUrl:\"https://accounts.google.com/.well-known/openid-configuration\",clientId:process.env.GOOGLE_CLIENT_ID,scopes:[\"openid\",\"profile\",\"email\"]},\n  github:{authorizeUrl:\"https://github.com/login/oauth/authorize\",tokenUrl:\"https://github.com/login/oauth/access_token\",clientId:process.env.GH_CLIENT_ID},\n};\nasync function oauthLogin(req,res){\n  const provider=PROVIDERS[req.params.provider];\n  const state=crypto.randomBytes(16).toString(\"hex\");\n  await redis.set(\"oauth:state:\"+state,JSON.stringify({provider:req.params.provider,redirect:req.query.redirect}),\"EX\",300);\n  const url=provider.authorizeUrl+\"?\"+new URLSearchParams({response_type:\"code\",client_id:provider.clientId,redirect_uri:\"https://api.example.com/oauth/callback\",scope:provider.scopes?.join(\" \"),state,});\n  res.redirect(url);\n}","description":"Multiple OAuth providers with secure state parameter."},{"question":"OAuth — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"OAuth — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"OAuth — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"OAuth — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"OAuth — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"OAuth — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["api-gateway"]["ag-logging"] = {"id":"ag-logging","title":"Logging","difficulty":"beginner","estimatedMinutes":13,"tldr":["API Gateway logging records all request/response metadata for debugging, monitoring, auditing, and security analysis.","Log at entry (request) and exit (response): method, path, status, latency, client IP, user ID, request ID, errors.","Structured JSON logging preferred: single-line, machine-parseable, with correlation IDs for distributed tracing.","Best practices: never log sensitive data (passwords, tokens, keys), add request ID per request, log level (debug/info/warn/error), sampling for high traffic."],"laymanDefinition":"API Gateway logging is like an airport security camera. Records who (IP, user id) passed through which gate (path) at what time, how long they took (latency), and whether they had items confiscated (errors). Protects and debugs.","deepDive":[{"heading":"Structured Logging in Gateways","text":"Single-line JSON per log event. Fields: timestamp, level, reqId, method, path, status, latency, user, clientIp, userAgent, error. Tools: ELK (Elasticsearch+Logstash+Kibana), Loki+Grafana, Datadog."},{"heading":"Request Correlation","text":"Unique request ID (X-Request-Id, Trace-Id) generated at gateway, passed to all downstream services. Enables tracing across microservices. Propagated via headers."},{"heading":"Log Levels and Sampling","text":"Level: debug (development), info (normal ops), warn (anomaly), error (failure). Sampling: log 100% errors, 10% warnings, 1% info. Adaptive sampling for high traffic to control volume."},{"heading":"Sensitive Data Scrubbing","text":"Before logging: remove Authorization header, X-API-Key, passwords, credit cards, PII. Regex patterns or field allowlist. Mask: \"Bearer ***\", \"sk_***\". Audit logs compliance."},{"heading":"Audit Logging","text":"Tamper-proof log of admin operations: who changed what when. Append-only, hash-chained, stored separately. For SOC2, PCI-DSS, GDPR compliance."}],"interviewAnswer":"Critical: structured JSON logs, request correlation IDs, never log sensitive data, sampling for volume control, distributed tracing with Gateway as root trace. Use ELK/Loki. Audit logs for compliance.","interviewQuestions":[{"question":"Why structured logging?","answer":"JSON logs are machine-parseable, searchable by field, and work with log aggregators like ELK."},{"question":"What is X-Request-Id?","answer":"Unique request identifier generated at gateway, propagated to all services for correlation."},{"question":"What fields in gateway logs?","answer":"timestamp, method, path, status, latency, clientIp, user, reqId, userAgent, error."},{"question":"What should NEVER be logged?","answer":"Passwords, tokens, API keys, credit cards, SSN, PII."},{"question":"What is log sampling?","answer":"Logging a percentage of requests to control volume and cost."},{"question":"Common log aggregators?","answer":"ELK (Elasticsearch/Logstash/Kibana), Loki+Grafana, Datadog, Splunk."},{"question":"What is audit logging?","answer":"Tamper-proof log of admin operations for compliance (SOC2, PCI-DSS)."},{"question":"How to propagate trace ID?","answer":"X-Request-Id or X-Trace-Id header passed from gateway to services."},{"question":"Log format recommendation?","answer":"Single-line JSON per event, one log entry per request-response cycle."},{"question":"What is log level?","answer":"debug/info/warn/error � severity indicator."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Logging</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Client</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Request</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"200\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Gateway</text><text x=\"200\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Log Entry</text><line x1=\"150\" y1=\"60\" x2=\"150\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"250\" y1=\"48\" x2=\"280\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Structured</text><text x=\"60\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">JSON log</text><rect x=\"10\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Scrub</text><text x=\"60\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">PII/Secrets</text><rect x=\"10\" y=\"140\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"156\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Correlate</text><text x=\"60\" y=\"168\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Request-Id</text><rect x=\"160\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"210\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Aggregator</text><text x=\"210\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">ELK/Loki</text><rect x=\"160\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"210\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Audit</text><text x=\"210\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Compliance</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Logging</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Structured JSON. Correlation IDs. No secrets. Sampling. ELK/Loki.</text></svg>","codeExamples":"<text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Logging: Structured JSON logs with correlation IDs, no secrets. ELK/Loki for aggregation. Essential for debugging and compliance.</text>","mcqQuestions":[{"title":"Structured Logger Middleware","useCase":"Log request and response.","code":"function requestLogger(req,res,next){\n  req.reqId=req.headers[\"x-request-id\"]||crypto.randomUUID();\n  res.setHeader(\"X-Request-Id\",req.reqId);\n  const start=Date.now();\n  res.on(\"finish\",()=>{\n    const latency=Date.now()-start;\n    const logEntry={\n      timestamp:new Date().toISOString(),level:\"info\",reqId:req.reqId,\n      method:req.method,path:req.path,status:res.statusCode,latency,\n      clientIp:req.ip,user:req.user?.id||\"anonymous\",\n      userAgent:req.headers[\"user-agent\"],\n      contentLength:res.getHeader(\"content-length\"),\n    };\n    const samplingRate=res.statusCode>=500?1.0:res.statusCode>=400?0.1:0.01;\n    if(Math.random()<samplingRate) console.log(JSON.stringify(logEntry));\n  });\n  next();\n}","description":"Structured JSON logger with sampling and correlation ID."},{"title":"Sensitive Data Scrubbing","useCase":"Secrets removed from logs.","code":"const SENSITIVE_HEADERS=[\"authorization\",\"x-api-key\",\"cookie\",\"set-cookie\",\"x-session-id\"];\nconst SENSITIVE_PATTERNS=[\n  /\\b(?:4[0-9]{12}(?:[0-9]{3})?|5[1-5][0-9]{14}|3[47][0-9]{13})\\b/g, // credit cards\n  /(?:password|secret|token|key)=?[\"']?[^&s\"']+/gi,\n  /Bearers+S+/gi,\n];\nfunction scrubSensitiveData(obj,path=\"\"){\n  if(typeof obj!==\"object\"||!obj) return obj;\n  const scrubbed={};\n  for(const [key,val] of Object.entries(obj)){\n    const k=key.toLowerCase();\n    if(SENSITIVE_HEADERS.includes(k)) scrubbed[key]=\"[REDACTED]\";\n    else if(typeof val===\"object\") scrubbed[key]=scrubSensitiveData(val,path+\".\"+key);\n    else{\n      let strVal=String(val);\n      for(const pattern of SENSITIVE_PATTERNS) strVal=strVal.replace(pattern,\"[REDACTED]\");\n      scrubbed[key]=strVal;\n    }\n  }\n  return scrubbed;\n}","description":"Scrubbing sensitive data before logging."},{"title":"Distributed Tracing with Correlation ID","useCase":"Trace across services.","code":"// Gateway � generate and propagate\nasync function tracingMiddleware(req,res,next){\n  req.traceId=req.headers[\"x-trace-id\"]||crypto.randomUUID();\n  req.spanId=crypto.randomUUID().slice(0,8);\n  res.setHeader(\"X-Trace-Id\",req.traceId);\n  const originalFetch=global.fetch;\n  global.fetch=function(url,opts={}){\n    opts.headers={...opts.headers,\"X-Trace-Id\":req.traceId,\"X-Span-Id\":req.spanId};\n    return originalFetch.call(this,url,opts);\n  };\n  next();\n}\n// Downstream service � propagate\nconst traceId=req.headers[\"x-trace-id\"]||crypto.randomUUID();\nlogger.info({msg:\"Processing request\",traceId,spanId:crypto.randomUUID().slice(0,8)});","description":"Distributed tracing with Trace and Span IDs propagated via headers."},{"title":"ELK Integration","useCase":"Ship logs to Elasticsearch.","code":"// Winston logger with Elasticsearch transport\nconst winston=require(\"winston\");\nrequire(\"winston-elasticsearch\");\nconst logger=winston.createLogger({\n  level:\"info\",format:winston.format.json(),\n  transports:[\n    new winston.transports.Console({format:winston.format.combine(winston.format.colorize(),winston.format.simple())}),\n    new ElasticsearchTransport({\n      level:\"info\",clientOpts:{node:\"https://elasticsearch:9200\",auth:{username:\"elastic\",password:process.env.ES_PWD}},\n      index:\"api-gateway-logs-\"+new Date().toISOString().slice(0,7),\n    })\n  ],\n});\nlogger.info({event:\"request\",method:req.method,path:req.path,status:200,latency:42});","description":"Winston logger shipping to Elasticsearch for ELK stack."},{"question":"Logging — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Logging — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Logging — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Logging — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Logging — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Logging — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};
TOPICS_DATA["api-gateway"]["ag-metrics"] = {"id":"ag-metrics","title":"Metrics","difficulty":"beginner","estimatedMinutes":14,"tldr":["API Gateway metrics are quantitative measurements tracking traffic, latency, errors, and resource usage for monitoring and alerting.","Four golden signals: Latency (response time), Traffic (requests/sec), Errors (rate), Saturation (resource usage). RED method: Rate, Errors, Duration.","Common metrics: requests per second (RPS), P50/P95/P99 latency, error rate (5xx,4xx), active connections, upstream latency, cache hit rate, rate limit usage.","Collect via Prometheus + Grafana or Datadog. Export metrics endpoint (/metrics). Histograms for latency distribution, counters for cumulative, gauges for current."],"laymanDefinition":"API Gateway metrics are like car dashboard gauges. Speed (RPS), RPM (latency), fuel (connections), check engine light (errors). Dashboard lets you drive faster without overheating.","deepDive":[{"heading":"Four Golden Signals","text":"Latency: time to serve request (P50/P95/P99). Traffic: requests per second (RPS). Errors: rate of failed requests (5xx,4xx). Saturation: how \"full\" gateway is (connections, CPU)."},{"heading":"RED Method","text":"Rate: requests per second. Errors: failed requests per second. Duration: distribution of response time. Simplifies monitoring: three metrics capture health."},{"heading":"Prometheus Metrics Types","text":"Counter: cumulative count (total requests, errors). Gauge: current value (active connections). Histogram: bucketed latency (p50, p95, p99). Summary: quantiles."},{"heading":"Upstream Metrics","text":"Track each backend service separately. Key: upstream_rps, upstream_latency, upstream_errors. Identify which service is slow. Circuit breaker data."},{"heading":"Alerting Thresholds","text":"P99 latency > 500ms. Error rate > 1% (5xx). RPS drop > 50%. Active connections > 80% of max. Cache hit rate < 50%. Rate limit threshold breached."}],"interviewAnswer":"Monitor four golden signals: Latency, Traffic, Errors, Saturation (USE) or Rate, Errors, Duration (RED). Use Prometheus histograms for latency. Alert on p99>500ms, error rate>1%. Upstream metrics for service-level visibility.","interviewQuestions":[{"question":"Four golden signals?","answer":"Latency, Traffic, Errors, Saturation."},{"question":"RED method components?","answer":"Rate (requests/sec), Errors (failed/sec), Duration (latency)."},{"question":"P50 vs P99?","answer":"P50: median latency. P99: 99th percentile (worst 1%)."},{"question":"Prometheus metric types?","answer":"Counter (cumulative), Gauge (current value), Histogram (bucketed), Summary (quantiles)."},{"question":"What is RPS?","answer":"Requests per second � measure of traffic."},{"question":"What to alert based on?","answer":"P99 latency, error rate, connection saturation, RPS anomalies."},{"question":"Why track upstream metrics?","answer":"Identify slow/malfunctioning backend services."},{"question":"Grafana vs Prometheus?","answer":"Prometheus: metrics storage. Grafana: dashboard visualization."},{"question":"Metrics endpoint?","answer":"/metrics � Prometheus scrapes this. Usually port 9090."},{"question":"What is saturation?","answer":"How \"full\" gateway is: connections, memory, CPU."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Metrics</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Gateway</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">App metrics</text><line x1=\"110\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"200\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Prometheus</text><text x=\"200\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Scrape</text><line x1=\"150\" y1=\"60\" x2=\"150\" y2=\"80\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><line x1=\"250\" y1=\"48\" x2=\"280\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"10\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Counters</text><text x=\"60\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Totals</text><rect x=\"10\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Histograms</text><text x=\"60\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Latencies</text><rect x=\"10\" y=\"140\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"60\" y=\"156\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Gauges</text><text x=\"60\" y=\"168\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cur. state</text><rect x=\"160\" y=\"70\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#6610f2\" stroke=\"#6610f2\" stroke-width=\"1\"/><text x=\"210\" y=\"86\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Grafana</text><text x=\"210\" y=\"98\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Dashboard</text><rect x=\"160\" y=\"105\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"210\" y=\"121\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Alerts</text><text x=\"210\" y=\"133\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Thresholds</text><rect x=\"290\" y=\"35\" width=\"190\" height=\"155\" rx=\"4\" fill=\"#17a2b8\" stroke=\"#17a2b8\" stroke-width=\"1\"/><text x=\"385\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Metrics</text><text x=\"385\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Four golden signals: Latency, Traffic, Errors, Saturation. Prometheus+Grafana. P50/P95/P99.</text></svg>","codeExamples":"<text x=\"240\" y=\"220\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Metrics: Four golden signals (Latency, Traffic, Errors, Saturation). Prometheus + Grafana. P50/P95/P99 latency. Alert on p99>500ms.</text>","mcqQuestions":[{"title":"Prometheus Metrics Middleware","useCase":"Expose /metrics.","code":"const promClient=require(\"prom-client\");\nconst register=new promClient.Registry();\npromClient.collectDefaultMetrics({register});\nconst httpRequestDuration=new promClient.Histogram({\n  name:\"http_request_duration_seconds\",help:\"Duration of HTTP requests in seconds\",\n  labelNames:[\"method\",\"path\",\"status\"],buckets:[0.01,0.05,0.1,0.25,0.5,1,2.5,5,10],\n  registers:[register],\n});\nconst httpRequestsTotal=new promClient.Counter({\n  name:\"http_requests_total\",help:\"Total number of HTTP requests\",\n  labelNames:[\"method\",\"path\",\"status\"],registers:[register],\n});\nconst activeConnections=new promClient.Gauge({\n  name:\"active_connections\",help:\"Number of active connections\",registers:[register],\n});\nasync function metricsMiddleware(req,res,next){\n  if(req.path===\"/metrics\"){\n    res.setHeader(\"Content-Type\",register.contentType);\n    res.end(await register.metrics());return;\n  }\n  activeConnections.inc();\n  const endTimer=httpRequestDuration.startTimer();res.on(\"finish\",()=>{\n    endTimer({method:req.method,path:req.route||req.path,status:res.statusCode});\n    httpRequestsTotal.inc({method:req.method,path:req.route||req.path,status:res.statusCode});\n    activeConnections.dec();\n  });next();\n}","description":"Prometheus metrics middleware with histogram, counter, gauge."},{"title":"Latency Monitoring","useCase":"Track p50/p95/p99.","code":"const p50=await promClient.util.getHistogramQuantile(0.5,histogram);\nconst p95=await promClient.util.getHistogramQuantile(0.95,histogram);\nconst p99=await promClient.util.getHistogramQuantile(0.99,histogram);\n// Or query Prometheus:\n// histogram_quantile(0.99, rate(http_request_duration_seconds_bucket[5m]))\n// Alert rules:\n// - alert: HighLatency\n//   expr: histogram_quantile(0.99, rate(http_request_duration_seconds_bucket[5m])) > 0.5\n//   for: 5m\n//   labels: { severity: critical }\n//   annotations: { summary: \"P99 latency > 500ms\" }","description":"Latency monitoring with Prometheus quantile queries and alerting."},{"title":"Upstream Health Metrics","useCase":"Track backend health.","code":"const upstreamLatency=new promClient.Histogram({\n  name:\"upstream_request_duration_seconds\",\n  help:\"Upstream request duration in seconds\",\n  labelNames:[\"upstream\",\"method\",\"status\"],buckets:[0.01,0.05,0.1,0.25,0.5,1,2.5,5,10],\n  registers:[register],\n});\nconst upstreamErrors=new promClient.Counter({\n  name:\"upstream_errors_total\",help:\"Total upstream errors\",\n  labelNames:[\"upstream\",\"error_type\"],registers:[register],\n});\n// Use in reverse proxy:\nasync function proxyToUpstream(req,res,target){\n  const endTimer=upstreamLatency.startTimer();\n  try{\n    const response=await fetch(target);\n    endTimer({upstream:target,method:req.method,status:response.status});\n    if(!response.ok) upstreamErrors.inc({upstream:target,error_type:\"http_\"+response.status});\n    res.status(response.status).send(await response.text());\n  }catch(err){\n    upstreamErrors.inc({upstream:target,error_type:\"connection\"});endTimer({upstream:target,method:req.method,status:0});\n    res.status(502).send(\"Bad Gateway\");\n  }\n}","description":"Upstream health metrics tracking latency and errors per backend."},{"title":"Grafana Dashboard JSON","useCase":"Example dashboard.","code":"// Grafana dashboard (JSON model)\n{\n  \"title\":\"API Gateway Dashboard\",\"panels\":[\n    {\"title\":\"RPS\",\"type\":\"graph\",\"targets\":[{\"expr\":\"rate(http_requests_total[5m])\",\"legendFormat\":\"{{method}} {{path}}\"}]},\n    {\"title\":\"P99 Latency\",\"type\":\"graph\",\"targets\":[{\"expr\":\"histogram_quantile(0.99,rate(http_request_duration_seconds_bucket[5m]))\",\"legendFormat\":\"P99\"}]},\n    {\"title\":\"Error Rate\",\"type\":\"graph\",\"targets\":[{\"expr\":\"rate(http_requests_total{status=~\"5..\"}[5m])/rate(http_requests_total[5m])\",\"legendFormat\":\"5xx %\"}]},\n    {\"title\":\"Active Connections\",\"type\":\"graph\",\"targets\":[{\"expr\":\"active_connections\",\"legendFormat\":\"connections\"}]},\n    {\"title\":\"Upstream Health\",\"type\":\"table\",\"targets\":[{\"expr\":\"upstream_errors_total\",\"legendFormat\":\"{{upstream}}\"}]},\n    {\"title\":\"Rate Limit Usage\",\"type\":\"graph\",\"targets\":[{\"expr\":\"rate_limit_usage_ratio\",\"legendFormat\":\"{{tier}}\"}]}\n  ],\"refresh\":\"10s\"}","description":"Grafana dashboard JSON for API Gateway metrics."},{"question":"Metrics — How to ensure reliability?","options":["Automated testing and monitoring","Manual checks only","No testing","Reactive fixes"],"answer":0,"explanation":"Automated testing and monitoring ensure consistent reliability."},{"question":"Metrics — What helps team collaboration?","options":["Shared workflows and visibility","Isolated work","No documentation","Siloed tools"],"answer":0,"explanation":"Shared workflows and visibility enable better collaboration."},{"question":"Metrics — What reduces errors most?","options":["Automation","Manual processes","Rushing","Bypassing reviews"],"answer":0,"explanation":"Automation consistently eliminates human errors."},{"question":"Metrics — What improves speed?","options":["Parallel execution and caching","Serial execution","No optimization","Manual steps"],"answer":0,"explanation":"Parallel execution and caching significantly improve speed."},{"question":"Metrics — What is key for monitoring?","options":["Metrics dashboards and alerts","No monitoring","Only error logs","Manual checks"],"answer":0,"explanation":"Metrics dashboards and alerts provide actionable insights."},{"question":"Metrics — What ensures quality?","options":["Automated testing in pipeline","No testing","Only manual QA","Skipping code review"],"answer":0,"explanation":"Automated testing integrated into the pipeline ensures consistent quality."}]};